INSERT INTO public.questions VALUES ('edf776ae-02f8-4039-af02-ed2535e75a75', '2a64c3b0-92cc-47db-9fc6-aa53bf5413f3', 'matrix', 'Questions 15-20', NULL, '<p>Label the map below.<br />Choose the correct letter, A- I, next to questions 15-20.</p>
<p><img decoding="async" src="data:image/png;base64," width="592" height="467" loading="lazy"></p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "Stage", "correctCategoryLetter": "F"}, {"itemText": "T-shirt Stand", "correctCategoryLetter": "A"}, {"itemText": "Bag Collection Area", "correctCategoryLetter": "B"}, {"itemText": "Information Centre", "correctCategoryLetter": "H"}, {"itemText": "Prize Draw Box", "correctCategoryLetter": "G"}, {"itemText": "Water Station", "correctCategoryLetter": "I"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('6baa22d1-482d-418d-b4ea-ebf7e0aae1e2', '08145313-65e3-4af6-adec-179805bee78c', 'radio', 'Questions 21–26', NULL, '<p style="text-align: left;">Choose the correct answers</p>
<p style="text-align: left;"><strong>Farmers’ attitudes to new developments in agriculture</strong></p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "the location of the farms"}, {"content": "the number of farmers"}, {"content": "the types of farming"}], "question": "What does Dr Owen advise Joel to include in the title of his project?   "}, {"correct": 2, "options": [{"content": "to see the farmers’ workplaces"}, {"content": "to limit the time he spends on the project"}, {"content": "to get fuller answers"}], "question": "Why has Joel decided to do face-to-face interviews?  "}, {"correct": 1, "options": [{"content": "by showing them a series of pictures. "}, {"content": "by asking them open questions. "}, {"content": "by sending them a checklist in advance."}], "question": "Joel agrees to investigate how farmers get information on new developments "}, {"correct": 0, "options": [{"content": "much of it is irrelevant.  "}, {"content": "it is often insufficient for farmers’ needs."}, {"content": "the wording is sometimes unclear."}], "question": "Concerning government communication with farmers, the speakers agree that "}, {"correct": 1, "options": [{"content": "leave investment decisions to their accountants. "}, {"content": "have too little time to calculate the costs of new methods. "}, {"content": "are reluctant to spend money on improvements."}], "question": "According to Joel’s reading about the cost of making changes, many British farmers "}, {"correct": 1, "options": [{"content": "are usually reluctant to make changes. "}, {"content": "make changes based on limited research. "}, {"content": "want plenty of evidence before they make changes."}], "question": "The survey of Australian sheep farmers found that most of them "}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a student called Joel talking to his tutor about his research into farmers’ attitudes towards new developments in agriculture. First you have some time to look at questions 21 to 26 on page five. Now listen carefully and answer questions 21 to 26.</p>\n<p data-path-to-node=\"4\"><strong>Dr Owen:</strong> Dr Owen, come in, Joel. Right, so how’s your research going? You’re looking at how farmers feel about new technology in agriculture, aren’t you?</p>\n<p data-path-to-node=\"5\"><span data-path-to-node=\"5,0\"><strong>Joel:</strong> Well, actually, it’s more general than that. </span><span class=\"citation-184\">I’m looking at their attitudes to a variety of new developments in agriculture. </span></p>\n<p data-path-to-node=\"7\"><strong>Dr Owen:</strong> Okay. Have you got a title for the project yet?</p>\n<p data-path-to-node=\"8\"><strong>Joel:</strong> I was thinking of something simple, like ‘Farmers’ attitudes towards the adoption of new farming practices’.</p>\n<p data-path-to-node=\"9\"><span data-path-to-node=\"9,0\"><strong>Dr Owen:</strong> Hmm, that’s possibly a bit too general. I think the title needs to be a bit more specific. What kind of farming will you be looking at? Well, that’ll vary actually, but I want to speak to each of the ten farmers in my sample, so I’ve chosen farms which are all in the same region. </span><span data-path-to-node=\"9,2\"><span class=\"citation-183\">Okay, well, I’d specify </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-183\">(21) where</span></strong></span><span class=\"citation-183\"> they are then. </span></span></p>\n<p data-path-to-node=\"10\"><strong>Joel:</strong> Right, I’ll amend the title to do that. Okay.</p>\n<p data-path-to-node=\"12\"><strong>Dr Owen:</strong> Is there any particular reason why you’ve decided to do face to face interviews? It’ll be quite time consuming, won’t it?</p>\n<p data-path-to-node=\"13\"><span data-path-to-node=\"13,0\"><strong>Joel:</strong> Yes, and I did consider doing telephone interviews for that reason, especially as it’s unnecessary for me to actually see the places where they work. </span><span data-path-to-node=\"13,2\"><span class=\"citation-182\">It’s just that, in my experience, a lot of farmers don’t like talking on the phone, so they’ll be more likely to talk </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-182\">(22) freely</span></strong></span><span class=\"citation-182\"> if I see them in person. </span></span></p>\n<p data-path-to-node=\"14\"><strong>Dr Owen:</strong> Yes, you’re probably right. Good. Then the first thing I want to investigate is how the farmers actually find out about new developments in agriculture that they might want to adopt—what sources they use. Right, so how are you going to do this?</p>\n<p data-path-to-node=\"15\"><strong>Joel:</strong> Well, I could make a checklist of sources of information for them to look at in advance, so they could tick off the ones they actually use—things like farming magazines, farm product advertisements, television and the internet, and so on.</p>\n<p data-path-to-node=\"16\"><span data-path-to-node=\"16,0\"><strong>Dr Owen:</strong> It might be more useful to ask them rather than show them a list. </span><span data-path-to-node=\"16,2\"><span class=\"citation-181\">A spontaneous response to one or two </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-181\">(23) open questions</span></strong></span><span class=\"citation-181\"><span style=\"background-color: #f1c40f;\"> </span>might give you a more accurate picture. </span></span></p>\n<p data-path-to-node=\"17\"><strong>Joel:</strong> Alright, I’ll do that then. Now talk me through some of the other issues you want to cover.</p>\n<p data-path-to-node=\"19\"><span data-path-to-node=\"19,0\"><strong>Dr Owen:</strong> Well, there’s the way the government communicates with farmers. </span><span data-path-to-node=\"19,2\"><span class=\"citation-180\">Right, well, one thing is farmers complain that the government sends out the same information to all of them, whether they’re poultry farmers or dairy farmers or arable farmers, so they get all this information but </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-180\">(24) Half of It</span></strong></span><span class=\"citation-180\"> doesn’t actually apply to them. </span></span></p>\n<p data-path-to-node=\"20\"><span data-path-to-node=\"20,0\"><strong>Joel:</strong> Exactly, so you could look at that. Right, then I wanted to look at attitudes of British farmers to the cost of making any changes on their farms. </span><span data-path-to-node=\"20,2\"><span class=\"citation-179\">According to articles I’ve read, farmers in Britain aren’t in principle against investing money in new machinery and new practices, but they’re actually just </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-179\">(25) Too busy</span></strong></span><span class=\"citation-179\"> to work out what the financial implications are. </span></span></p>\n<p data-path-to-node=\"21\"><strong>Dr Owen:</strong> Yes, and a lot of them don’t seem to consider getting financial advice from their accountants about it either. Right.</p>\n<p data-path-to-node=\"23\"><span data-path-to-node=\"23,0\"><strong>Dr Owen:</strong> There’s also been some research in Australia on sheep rearing practices. I can give you the reference if you like. Basically, it appears that the majority of Australian sheep farmers are willing to risk adopting new practices on the basis of just a <span style=\"background-color: #f1c40f;\"><strong>(26) few pieces of research</strong></span>. </span><span class=\"citation-178\">They don’t usually wait until the evidence in favour of the changes is overwhelming; they’re quite happy to act before then, so they can get ahead of the game. </span></p>\n<p data-path-to-node=\"24\"><strong>Joel:</strong> Okay, I’ll take a look at that, thanks.</p>\n<p data-path-to-node=\"27\"><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions 27 to 30 on page six. Now listen and answer questions 27 to thirty.</p>\n<p data-path-to-node=\"28\"><span data-path-to-node=\"28,0\"><strong>Dr Owen:</strong> We said we’d also look at some of the reading material you’ve been reviewing. Yes, I had another look at <em>Contemporary Farming Manual</em>, which is clearly bang up to date. </span><span data-path-to-node=\"28,2\"><span class=\"citation-177\">It covers a lot of things a farmer might want to know, but it’s so </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-177\">(27) dull</span></strong></span></span><span style=\"background-color: #f1c40f;\" data-path-to-node=\"28,4\">.</span></p>\n<p data-path-to-node=\"29\"><strong>Joel:</strong> Absolutely, I found It really hard going and I can’t imagine any farmer wading through it. There aren’t even any decent pictures. Did you have time to look at <em>Running a Small Farm</em>?</p>\n<p data-path-to-node=\"30\"><span data-path-to-node=\"30,0\"><strong>Dr Owen:</strong> Yes, although I only read bits of it because, despite being entertaining, it wasn’t very academic. </span><span data-path-to-node=\"30,2\"><span class=\"citation-176\">I know, and a lot of the information is either<span style=\"background-color: #f1c40f;\"> </span></span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-176\">(28) misleading or simply wrong</span></strong></span></span><span data-path-to-node=\"30,4\">. I’m surprised it got published at all.I don’t imagine the farming press will rate it very highly. </span></p>\n<p data-path-to-node=\"31\"><span data-path-to-node=\"31,0\"><strong>Joel:</strong> Hmm. You recommend <em>Agriculture and Economics</em>. </span><span data-path-to-node=\"31,2\"><span class=\"citation-175\">Hmm, I expected that it would be really difficult—the title’s a bit off putting—but I thought it was</span><span class=\"citation-175\"> brilliant</span><span class=\"citation-175\"> so I’ve bought it. </span></span></p>\n<p data-path-to-node=\"33\"><span data-path-to-node=\"33,0\"><strong><span class=\"citation-174\">Dr Owen:</span></strong><span class=\"citation-174\"> Yes, some people think it relies too heavily on farming practices in specific parts of the world, but the theories that underpin these are universal, and that’s why </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-174\">(29) it’s a required textbook</span></strong></span><span class=\"citation-174\"> for anyone studying agriculture. </span></span><span data-path-to-node=\"33,2\"> Right, what else did you come across?</span></p>\n<p data-path-to-node=\"34\"><span data-path-to-node=\"34,0\"><strong>Joel:</strong> I borrowed <em>How to Survive in Farming</em> from the library. </span><span data-path-to-node=\"34,2\"><span class=\"citation-173\">I thought it would be interesting background and I liked the informal style, but<span style=\"background-color: #f1c40f;\"> </span></span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-173\">(30) it turned out to have been written years ago</span></strong></span></span><span style=\"background-color: #f1c40f;\" data-path-to-node=\"34,4\">.</span></p>\n<p data-path-to-node=\"36\"><span data-path-to-node=\"36,0\"><strong><span class=\"citation-172\">Dr Owen:</span></strong><span class=\"citation-172\"> Yes, and like everything else, farming fashions have changed, so </span><span style=\"background-color: #f1c40f;\"><strong><span class=\"citation-172\">(30) it’s badly in need of a new edition</span></strong></span></span><span data-path-to-node=\"36,2\"><span style=\"background-color: #f1c40f;\">. </span>Can I ask you a question about…</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('faab877b-f7e8-49a3-98f3-7c84d0b2d2a5', 'e8bef659-e65c-4a18-a2f3-a67344f4a3de', 'radio', 'Question 40', '', '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. Children make an exciting archaeological discovery"}, {"option_text": "B. Archaeology is becoming a new hobby for children"}, {"option_text": "C. The benefits for children of working with archaeologists"}, {"option_text": "D. Communities appreciate the teachings of archaeologists"}], "question": "What would be a suitable title for the article?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">40. Đáp án: {C} The benefits for children of working with archaeologists</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The project meant the children could <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"49\">lead their own historical investigations</strong> and <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"94\">expand their understanding</strong>…” (Đoạn F) và “…creating a <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"152\">real-life context</strong> for them to play an <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"190\">active part in learning</strong> – educating not just themselves but their community too.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xuyên suốt bài đọc, tác giả không chỉ kể về một khám phá đơn lẻ mà tập trung vào những giá trị tích cực (lợi ích) mà trẻ em nhận được: từ việc thay đổi nhận thức lịch sử, rèn luyện kỹ năng nghiên cứu tài liệu gốc, đến việc tự tay tổ chức triển lãm và kết nối với thế hệ đi trước.</p>\n</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('0f7256fe-765f-4949-9679-9393fb9617c2', '6e4cdc6e-9136-4f71-904f-09dcbc11ce90', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: left;"><strong>ABORIGINAL TEXTILE DESIGN</strong></p>
<p><strong>Ernabella Arts Centre</strong></p>
<p>– Artists produce craft and learn new techniques</p>
<p>– Initially, artists produced rugs made from {wool}</p>
<p>– Later artists made batik and screen-printed fabrics</p>
<p><strong>Tiwi Designs</strong></p>
<p>– Early designs included {bird} images</p>
<p>– Designs are linked to traditional beliefs, e g. some designs are believed to bring {rain}</p>
<p><strong>Jimmy Pike</strong></p>
<p>– Inspired by the Australian landscape, especially the {desert}</p>
<p>– Started creating art when he was in {prison}</p>
<p>– His textiles were used to make {clothing}</p>
<p><strong>Bronwyn Bancroft</strong></p>
<p>– Her work is a modern look at {family} and nature</p>
<p>– 1995 – painted a successful Aboriginal athlete’s jeans with lizards and a {rainbow}</p>
<p>– 2001 – designed a ‘Journey of a Nation’ parade outfit with part of a {snake} on it</p>
<p><strong>Copyright Issues</strong></p>
<p>– Exploiting Aboriginal imagery affects the artists and the cultural group, e.g. ‘The {Carpet} Case’</p>
</div>
</div>', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear part of a lecture given by an art and design lecturer on the topic of Aboriginal textile design in Australia. First you have some time to look at questions 31 to 40 on page seven. Now listen carefully and answer questions 31 to forty.</p>\n<p><strong>Lecturer:</strong> The indigenous people of Australia or Aborigines have a long history of using animal and plant fibres to make a variety of fabric over the years. Their traditional designs and stories have been incorporated into various textiles. The Ernabella Arts Centre is a place where local Aborigines can produce their traditional craft and also learn new techniques to decorate fabric. For the first thirty years, the artists crafted rugs working with <span style=\"background-color: #f1c40f;\"><strong>(31) wool</strong>.</span> These rugs incorporated their own unique designs. However, as they became less economical to produce, the artists were introduced to batik, which is an Indonesian method of dyeing textiles.Batik is quicker than weaving, so many of the Ernabella artists started to produce it themselves. Screen printing was later introduced to the Centre and Ernabella’s artists were commissioned to produce fabric for <span style=\"background-color: #f1c40f;\"><strong>(32) furniture</strong></span> that was to be used at popular tourist destinations such as the National Park offices at Uluru.</p>\n<p><strong>Lecturer:</strong> Screen printing has also been used successfully by the Tiwi people who live on islands north of Darwin. Their company, Tiwi Designs, produces fabric that is inspired by their surroundings. For example, they incorporated<span style=\"background-color: #f1c40f;\"> <strong>(33) Bird</strong></span> motifs into their early designs. Tiwi art, culture, and language are very different from those of mainland Aboriginal groups. The patterns on their fabric are related to the beliefs and legends in their culture. For example, some textile designs are chosen because they are thought to cause<span style=\"background-color: #f1c40f;\"> <strong>(34) rain</strong></span>.</p>\n<p><strong>Lecturer:</strong> Another successful Aboriginal design company was founded by <strong>Jimmy Pike</strong>. His dynamic prints, paintings, and fabrics are greatly influenced by the Australian landscape, in particular that of the <span style=\"background-color: #f1c40f;\"><strong>(35) desert</strong></span>, which is often featured in his work. Pike worked with acrylic paint, oil pastels, and screen printing.Surprisingly, Jimmy Pike’s life as an artist began in <span style=\"background-color: #f1c40f;\"><strong>(36) prison</strong></span>, where he was serving a sentence for murder. The art teachers there recognized his talent and gave him the technical skills he needed to become a successful artist. After Pike’s release, he started his own company, aiming to create a product that would sell well commercially, but still retain its Aboriginal cultural identity. Eventually, he decided to bring his artwork onto textiles, which were used to produce <span style=\"background-color: #f1c40f;\"><strong>(37) clothing</strong></span>.The designs he selected were transferred onto cotton and had both a strong linear character and a good colour range.</p>\n<p><strong>Lecturer:</strong> <strong>Bronwyn Bancroft</strong> is one of the most successful Aboriginal artists and designers to date.She has produced a great deal of artwork and textiles, and many of her paintings are held by Australian art galleries. Her work reflects her Aboriginal roots but always with a contemporary, fresh view of <span style=\"background-color: #f1c40f;\"><strong>(38) family</strong></span> and the natural environment. In nineteen ninety-five, she was chosen by a charity organisation to paint a pair of jeans owned by Kathy Freeman, a famous Aboriginal Australian athlete.She used imagery of lizards moving quickly over the Australian terrain, and she added a <span style=\"background-color: #f1c40f;\"><strong>(39) Rainbow</strong></span>, which represents the optimism that Kathy symbolizes for all Aboriginal people. In two thousand and one, she was chosen to design costumes for the opening of the biggest street parade ever held in Australia, the &#8220;Journey of a Nation Parade&#8221;. The people in Bancroft&#8217;s section of the parade all wore an outfit she designed. It featured the image of a <span style=\"background-color: #f1c40f;\"><strong>(40) snake</strong></span> that had no head or tail, to represent an ongoing culture.</p>\n<p><strong>Lecturer:</strong> Exploitation of creative work can be a problem for any artist, and copyright laws exist to protect individual artists  from the unauthorized use of his or her work. This issue is often more complex for Aboriginal artists, as the symbols and motifs used in their designs also hold cultural significance for them. An example of this was when a businessman had rugs made overseas incorporating images stolen from Aboriginal paintings. The <strong>Carpet Case</strong> as it became known was taken to court, where luckily the artists won.</p>\n<p><strong>Narrator:</strong> That is the end of Section 4. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ff518b2a-ea5b-460e-999f-59ad5a89b3e7', '7d440b76-b5c4-4654-b465-f4612ba90311', 'fillup', 'Questions 1-10', '<p>Complete the table below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>The London Relocation Services</strong></span></p>
<p><strong>Customer’s name: </strong>Anna Woods</p>
<p><strong>Customer’s personal details</strong></p>
<p>– Current address 118 {Fordyce} Park, Ballysillan</p>
<p>– Postcode: BT149BJ</p>
<p>– Phone No: {07840051963} (Mobile)</p>
<p><strong>Other information</strong></p>
<p>– Anna is hoping to find work as a {nurse}</p>
<p>– She needs to find a {primary} school for her son</p>
<p><strong>Requirements for the new property</strong></p>
<p>Location</p>
<p>– Her preferred location is in the {south} of the city.</p>
<p>– Her husband would like to be new a {station}</p>
<p>– Her son would prefer to be close to a {park}</p>
<p>Property details:</p>
<p>– She would like to live in a {house}</p>
<p>– She would prefers {three | 3} bedrooms</p>
<p>– A small {office} is also desirable</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a telephone conversation between a woman who is moving to London and an employee of a relocation service. First you have some time to look at questions one to seven. Now listen carefully and answer questions one to seven.</p>\n<p data-path-to-node=\"4\"><strong>Daniel:</strong> London Relocation Services, Daniel speaking. How may I help you?</p>\n<p data-path-to-node=\"5\"><strong>Anna:</strong> Good morning. My family and I are moving to London later this year and I wonder if you can help.</p>\n<p data-path-to-node=\"6\"><strong>Daniel:</strong> Sure. First of all, I’ll need to get some personal details. May I take your full name please?</p>\n<p data-path-to-node=\"7\"><strong>Anna:</strong> It’s Anna Woods.</p>\n<p data-path-to-node=\"8\"><strong>Daniel:</strong> Thanks. Where are you moving from?</p>\n<p data-path-to-node=\"9\"><strong>Anna:</strong> Northern Ireland, just outside Belfast, actually.</p>\n<p data-path-to-node=\"10\"><strong>Daniel:</strong> Right. And what’s your current address?</p>\n<p data-path-to-node=\"11\"><strong>Anna:</strong> It’s 118<span style=\"background-color: #f1c40f;\"> <strong>(1) Fordyce</strong></span> Park. I’ll spell that for you. It’s F-O-R-D-Y-C-E and that’s in Ballysillan.</p>\n<p data-path-to-node=\"12\"><strong>Daniel:</strong> And what’s the postcode?</p>\n<p data-path-to-node=\"13\"><strong>Anna:</strong> It’s BT14 9BJ.</p>\n<p data-path-to-node=\"14\"><strong>Daniel:</strong> Alright. And could I take a contact phone number?</p>\n<p data-path-to-node=\"15\"><strong>Anna:</strong> I’ll give you my mobile number as you can get me on that anytime. It’s<span style=\"background-color: #f1c40f;\"> <strong>(2) 07840051963</strong>.</span></p>\n<p data-path-to-node=\"16\"><strong>Daniel:</strong> Great. Got that. Now we always like to get a bit more information about the families that we’re moving. It helps with the search. Are you moving for work?</p>\n<p data-path-to-node=\"17\"><strong>Anna:</strong> Yes, my husband’s just got a new job in London.</p>\n<p data-path-to-node=\"18\"><strong>Daniel:</strong> And what about you? Do you work?</p>\n<p data-path-to-node=\"19\"><strong>Anna:</strong> Well, I’ve been working as a teaching assistant recently. But I’m actually a qualified <span style=\"background-color: #f1c40f;\"><strong>(3) nurse</strong>,</span> and I’d like to get back into that if possible.</p>\n<p data-path-to-node=\"20\"><strong>Daniel:</strong> Right. And do you have any children?</p>\n<p data-path-to-node=\"21\"><strong>Anna:</strong> Yes, a son. So we need to find a school for him.</p>\n<p data-path-to-node=\"22\"><strong>Daniel:</strong> Is it a secondary school you’ll be looking for?</p>\n<p data-path-to-node=\"23\"><strong>Anna:</strong> No, he’s still in <span style=\"background-color: #f1c40f;\"><strong>(4) primary</strong></span> school. He’s not quite at the secondary level yet.</p>\n<p data-path-to-node=\"24\"><strong>Daniel:</strong> Fine. So let’s go on to talk about your requirements for the property. Do you have a preferred location? Is your husband’s job in the center?</p>\n<p data-path-to-node=\"25\"><strong>Anna:</strong> No, it’s in East London, but we’d rather live somewhere quieter.</p>\n<p data-path-to-node=\"26\"><strong>Daniel:</strong> Sure. There are some lovely areas in the <span style=\"background-color: #f1c40f;\"><strong>(5) South</strong>.</span></p>\n<p data-path-to-node=\"27\"><strong>Anna:</strong> OK, that sounds great. Now my husband doesn’t want to spend too long commuting to work every day.</p>\n<p data-path-to-node=\"28\"><strong>Daniel:</strong> So I imagine that ideally he’d like to be not too far from a <span style=\"background-color: #f1c40f;\"><strong>(6) station</strong></span> then.</p>\n<p data-path-to-node=\"29\"><strong>Anna:</strong> Yes, he drives now, but I guess that’s not going to be possible and he’s not keen on buses.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Daniel:</strong> Oh, what about you or your son? Do you have any preferences? Does your son do any sport, for example?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Anna:</strong> He’s quite active, so I’m sure he’d love a<strong data-path-to-node=\"30\" data-index-in-node=\"49\"> <span style=\"background-color: #f1c40f;\">(7) </span></strong><strong><span style=\"background-color: #f1c40f;\">park</span> </strong>nearby to run around in. He doesn’t do swimming or anything like that.</p>\n<p data-path-to-node=\"31\"><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions eight to ten. Now listen and answer questions eight to ten.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Daniel:</strong> So what sort of property do you have in mind?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Anna:</strong> We have friends who live in an amazing flat over there, but as we’ve always lived in a<span style=\"background-color: #f1c40f;\"> <strong>(8) </strong><strong data-path-to-node=\"34\" data-index-in-node=\"93\">house</strong></span>, I think we’ll stick with that. We’d find it hard to adapt to a flat.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Daniel:</strong> OK. And size-wise, how many bedrooms would you like?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Anna:</strong> Well, there’s just myself, my husband and our son.</p>\n<p data-path-to-node=\"31\"><strong> Daniel:</strong>So you definitely need a two-bedroom property. But how about having a guest room? I might be able to find a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"36\" data-index-in-node=\"165\">(9) three-bedroom</strong></span> property for you.</p>\n<p data-path-to-node=\"31\"><strong>Anna:</strong> Yes, that would be ideal. We’re sure to have family visiting often.</p>\n<p data-path-to-node=\"31\"><strong>Daniel:</strong> All right, I’ve made a note of that now, are there any other requirements for your new property?</p>\n<p data-path-to-node=\"31\"><strong>Anna:</strong> Well, it’s not essential. But it would be handy to have a small <span style=\"background-color: #f1c40f;\"><strong>(10) office</strong></span> for when my husband works from home. It doesn’t need to be a big one. I guess it all comes down to budget.</p>\n<p data-path-to-node=\"31\"><strong>Daniel:</strong> Yes. OK. Anna. Well, I’ve certainly got enough to be getting on with, and I will.</p>\n<p data-path-to-node=\"43\"><strong>Narrator:</strong> That is the end of Part One. You now have one minute to check your answers to Part One.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('16d9c56c-61d3-4772-a406-b1857b09c220', 'e7748f69-4c5b-4a75-8770-b62aea4c3860', 'fillup', 'Questions 21-27', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p> Doing unpaid work will help you learn what {expectations} employers have in Australia.</p>
<p> Through volunteer or work experience, you can find people to supply {references} when you are applying for work or courses.</p>
<p> You need to develop a {contact network} to help you access information and advice about jobs.</p>
<p> By talking to people like {family members}, you may learn of opportunities in your chosen field.</p>
<p> Try to find a company with a {formal structure} for its training programme.</p>
<p> A work placement should offer experience in a number of different {roles}</p>
<p> You should find out if there is an orientation, and a company {trainer} who is available to help you.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. Doing unpaid work will help you learn what {expectations} employers have in Australia.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…will improve our understanding of the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"53\">expectations of Australian employers</strong>.”</em> (Đoạn 1)</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Improve our understanding” đồng nghĩa với “help you learn”. Thứ mà bạn sẽ hiểu rõ hơn chính là những kỳ vọng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"123\">expectations</strong>) của các chủ doanh nghiệp Úc.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Through volunteer or work experience, you can find people to supply {references} when you are applying for work or courses.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…give you the chance to meet appropriate <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"55\">referees</strong> who you can ask to provide <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"91\">references</strong> for future job or study applications.”</em> (Đoạn 2)</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Applying for work or courses” tương ứng với “job or study applications”. Những người xác nhận năng lực cho bạn (referees) sẽ là nguồn cung cấp các thư giới thiệu/tham chiếu (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"187\">references</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. You need to develop a {contact network} to help you access information and advice about jobs.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Volunteering can help you build this <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"49\">contact network</strong>. These contacts will be of use to you when it comes to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"120\">advice</strong> on how to advance your career…”</em> (Đoạn 3)</li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để có được lời khuyên và thông tin, bạn cần xây dựng một mạng lưới liên lạc (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"89\">contact network</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. By talking to people like {family members}, you may learn of opportunities in your chosen field.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Research… by <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"27\">asking people, such as family members</strong>, if they know of any companies… in <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"102\">career areas that you are interested in</strong>.”</em> (Đoạn 5)</li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Chosen field” tương ứng với “career areas you are interested in”. Cách để biết thông tin là hỏi những người thân thiết như các thành viên trong gia đình (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"167\">family members</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. Try to find a company with a {formal structure} for its training programme.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“You are looking for an organisation where the work experience or volunteer training scheme has a <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"109\">formal structure</strong>.”</em> (Đoạn 6)</li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Training programme” tương ứng với “training scheme”. Đặc điểm bạn cần tìm kiếm ở đây là một cấu trúc chính thức (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"126\">formal structure</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. A work placement should offer experience in a number of different {roles}.</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“…and that you are exposed to a <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"45\">variety of roles</strong>.”</em> (Đoạn 6)</li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A number of different” đồng nghĩa với “a variety of”. Một kỳ thực tập tốt cần cho bạn trải nghiệm ở nhiều vị trí/vai trò (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"135\">roles</strong>) khác nhau.</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">27. You should find out if there is an orientation, and a company {trainer} who is available to help you.</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“…find out in advance about provision of an <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"57\">induction</strong> and if the company employs a <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"96\">trainer</strong> to provide in-house training…”</em> (Đoạn 7)</li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Orientation” (buổi định hướng) đồng nghĩa với “induction”. Người có sẵn để giúp đỡ/đào tạo bạn chính là người huấn luyện viên (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"140\">trainer</strong>).</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('31b16083-d0b5-47f9-84c6-6295b50d72bf', 'b90dacd6-a05c-49e3-b856-241c6e6b9b5d', 'radio', 'Questions 11-14', NULL, '<p>Choose the correct answer</p>
<p><span style="font-size: 12pt;"><strong>Starting work at Hollies supermarket</strong></span></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "be aware of the importance of teamwork"}, {"content": "be flexible in terms of their availability."}, {"content": "be capable of lifting heavy loads."}], "question": "The supervisor starts her talk by explaining that employees have to"}, {"correct": 0, "options": [{"content": "decide for themselves what needs doing"}, {"content": "postpone their scheduled break"}, {"content": "report minor accidents quickly."}], "question": "The supervisor says that when the supermarket is very busy, employees must"}, {"correct": 2, "options": [{"content": "helps everyone in the supermarket to relax"}, {"content": "encourages customers to spend more"}, {"content": "improves work effectiveness"}], "question": "The supervisor explains that when employees have a positive attitude, it"}, {"correct": 1, "options": [{"content": "reports an employee to the manager."}, {"content": "delays other shoppers."}, {"content": "refuses to wait their turn."}], "question": "The supervisor says it is essential to stay calm when a customer"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong>Questions 11–14</strong></p>\n<p data-path-to-node=\"4\"><strong>Narrator:</strong> You will hear a supervisor at Holly’s Supermarket talking to a group of new employees. First you have some time to look at questions eleven to fourteen. Now listen carefully and answer questions eleven to fourteen.</p>\n<p data-path-to-node=\"6\"><strong>Supervisor:</strong> Welcome to Holly’s Supermarket! I’m sure you’ll all enjoy working in our dedicated team here. So what will you be doing? Well, we’re open Monday through Sunday, so you’ll need to be able to work weekends as well as irregular weekday shifts. These sometimes start at 5 a.m. or finish at 11 p.m. <span style=\"background-color: #f1c40f;\"><strong>(11) (be flexible in terms of their availability)</strong>.</span> Your duties will include checking and unpacking lorry deliveries, as well as working on the shop floor, stocking shelves and so on. But you’ll only be required to do manual lifting if the goods are light.</p>\n<p data-path-to-node=\"8\"><strong>Supervisor:</strong> When the store is very busy, you’ll also have to assess changing priorities <span style=\"background-color: #f1c40f;\"><strong>(12) (decide for themselves what needs doing)</strong>. </span>For example, if there’s a queue at the tills, you’ll jump on a spare one to help. If you notice something’s been spilt and the surface is a little bit wet, you’ll get a mop to clean it up; no need to check with the manager first. Similarly, if bakery items are selling quickly, you’ll help cook some more, and if a customer can’t find say the apples, you’ll instantly leave what you’re doing and show them. But you’ll still get time off to relax too, of course.</p>\n<p data-path-to-node=\"10\"><strong>Supervisor:</strong> We pride ourselves on a positive attitude here. A little small talk shows you’re interested in the customers and are providing excellent service, just as long as you don’t overdo it and keep another customer waiting. And always smile. It forces you to stay positive, and being generally upbeat <span style=\"background-color: #f1c40f;\"><strong>(13) makes your whole team happy too. This increases efficiency</strong></span> and gives a good impression to customers. <span style=\"background-color: #f1c40f;\"><strong>(13) (improves work effectiveness)</strong>. </span>If it’s quiet, help someone pack their bags. Customers really appreciate it, especially when they’ve bought more than they expected to.</p>\n<p data-path-to-node=\"12\"><strong>Supervisor:</strong> Staying calm’s also a necessity. If a customer’s unhappy for any reason, keep cool and call for a supervisor to help defuse a situation if things are getting out of hand. Occasionally when working tills, you’ll find yourself waiting for someone to extract their wallet from the bottom of a cluttered bag while a long queue of annoyed customers builds up. You have to make sure, however hard it might be, that you <span style=\"background-color: #f1c40f;\"><strong>(14) remain composed</strong>.</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('284ac11c-cf38-425d-97ac-059e3b4f0b14', '28413af2-cd90-4143-8bb1-dbd0d235c224', 'fillup', 'Questions 7–13', '<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p><strong>The Commercial Development of Rubber</strong></p>
<p>Early European travellers gave accounts of various rubber objects in use in Central and South America, and these accounts created interest in the commercial exploitation of rubber. In 1818, {waterproof cloth} was produced using rubber, and in 1820 a machine was invented for recycling {waste strips} of rubber. Over the next few years, other attempts were made to improve rubber, but some problems remained. For example, rubber products smelt bad when they were dissolved, and could turn either soft or {rigid} depending on the temperature. However, in 1839 a new process to {stabilise} the substance greatly increased its potential. For example, rubber was used in the creation of the {steam engines} industry during the Industrial Revolution. Then in 1888 the {first pneumatic tyre|pneumatic tyre} was developed, and a few years later the {mass production} of the motor car began.</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong class=\"\">7. In 1818, waterproof cloth was produced using rubber</strong></p>\n<ul>\n<li><strong class=\"\">Đáp án:</strong> <strong class=\"\">waterproof cloth</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 2) “In 1818 a British medical student named James Syme first used rubber to make </span><strong class=\"\">waterproof cloth</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n</ul>\n<p><strong class=\"\">8. …a machine was invented for recycling waste strips of rubber.</strong></p>\n<ul>\n<li><strong class=\"\">Đáp án:</strong> <strong class=\"\">waste strips</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 2) “…</span><span class=\"\">invented a machine he called the ‘piokle’,</span><span class=\"\"> which chewed up </span><strong class=\"\">waste strips</strong><span class=\"\"> for re-use.</span><span class=\"\">“</span></li>\n</ul>\n<p><strong class=\"\">9. …rubber products smelt bad when they were dissolved, and could turn either soft or rigid depending on the temperature.</strong></p>\n<ul>\n<li><strong class=\"\">Đáp án:</strong> <strong class=\"\">rigid</strong></li>\n<li class=\"animating\"><strong>Dẫn chứng:</strong> (Đoạn 3) “They also became pliant when warm and <strong>rigid</strong> when cold.” (Pliant đồng nghĩa với soft – mềm).</li>\n</ul>\n<p><strong>10. However, in 1839 a new process to stabilise the substance greatly increased its potential.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>stabilise</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) “…Charles Goodyear discovered that it was possible to <strong>stabilise</strong> rubber by mixing it with sulphur…”</li>\n</ul>\n<p><strong>11. For example, rubber was used in the creation of the steam engines industry during the Industrial Revolution.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>steam engines</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) “It played an important role in the Industrial Revolution, being employed in the <strong>steam engines</strong> found in factories…”</li>\n</ul>\n<p><strong>12. Then in 1888 the pneumatic tyre was developed, and a few years later the mass production of the motor car began.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>pneumatic tyre</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “…John Boyd Dunlop produced the first <strong>pneumatic tyre</strong>.”</li>\n</ul>\n<p><strong>13. …and a few years later the mass production of the motor car began.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>mass production</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “…and with the <strong>mass production</strong> of cars just over the horizon…”</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('bdbff541-b2d1-40bc-8201-03b92bc1f671', 'b90dacd6-a05c-49e3-b856-241c6e6b9b5d', 'matrix', 'Questions 15–20', NULL, '<p>Questions 15–20</p>
<p>Label the plan below.</p>
<p><img decoding="async" src="data:image/png;base64," width="471" height="484" loading="lazy"></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "Staff entrance", "correctCategoryLetter": "A"}, {"itemText": "Manager''s office", "correctCategoryLetter": "D"}, {"itemText": " Storage and unpacking", "correctCategoryLetter": "B"}, {"itemText": "Kitchen", "correctCategoryLetter": "E"}, {"itemText": "Cleaning equipment", "correctCategoryLetter": "G"}, {"itemText": "Staff relaxation area", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}, {"categoryText": "J", "categoryLetter": "J"}]}', '[{"content": "<h2>(Questions 15–20)</h2>\n<p data-path-to-node=\"4\"><strong>Narrator:</strong> Before you hear the rest of the talk, you have some time to look at questions fifteen to twenty. Now listen and answer questions fifteen to twenty.</p>\n<p data-path-to-node=\"6\"><strong>Supervisor:</strong> So, now let’s look at the plan of the supermarket. Have you all got your plans? Okay, good. We’ll start with the<span style=\"background-color: #f1c40f;\"> <strong>(15) Staff entrance (A)</strong></span>. Today you came in through the customer entrance, clearly marked on the bottom of your plan, but in future, you’ll enter through the door in the <strong>top left hand corner</strong> of the diagram. Please don’t confuse this with the emergency exits in the top right hand corner and bottom left; it’s very important that these are kept clear at all times.</p>\n<p data-path-to-node=\"8\"><strong>Supervisor:</strong> Regarding the <span style=\"background-color: #f1c40f;\"><strong>(16) Manager’s office (D)</strong></span>, some of you may have attended interviews here when it was next to the newspaper and magazine sales area. However, it’s recently been moved and is now the <strong>circular space</strong> marked on the <strong>right</strong> of your plans. When the manager’s not on the shop floor, that’s where you’ll find her.</p>\n<p data-path-to-node=\"10\"><strong>Supervisor:</strong> The <span style=\"background-color: #f1c40f;\"><strong>(17) Storage and unpacking area (B)</strong></span>—you may be asked to help out here both before and after opening hours. This is represented by the <strong>largest of the four rectangles in the top section</strong> of the plan. It tends to get very busy there at times, so please be careful on entering and leaving this area.</p>\n<p data-path-to-node=\"12\"><strong>Supervisor:</strong> There’s a <span style=\"background-color: #f1c40f;\"><strong>(18) Kitchen (E)</strong></span> on site where food and drinks are prepared for customers.It has specialist staff, but some of you may have to fill in occasionally. On the plan, it’s shown by the <strong>triangular shape to the left of the tinned goods aisle</strong>. It’s very busy as many customers like to take a break in the café and read a newspaper before or after doing their shopping.</p>\n<p data-path-to-node=\"14\"><strong>Supervisor:</strong> Cleaning equipment is stored in a cupboard. It’s the <span style=\"background-color: #f1c40f;\"><strong>(19) smaller of the two squares (G)</strong> </span>marked near the vegetable and fruit section and can come in very handy. You’d be surprised how often we have to mop up squashed tomatoes or grapes.</p>\n<p data-path-to-node=\"16\"><strong>Supervisor:</strong> Finally, you’ll be pleased to know there’s a separate <span style=\"background-color: #f1c40f;\"><strong>(20) staff relaxation area (C)</strong></span>. This is at the <strong>top</strong> of your plan, between the frozen goods section and the exit. As well as comfortable chairs, there’s also a microwave for heating up snacks and a drinks dispenser.So let’s go there now.</p>\n<p data-path-to-node=\"18\"><strong>Narrator:</strong> That is the end of Part Two. You now have thirty seconds to check your answers to Part Two.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ceeb4b17-34db-4213-9000-46a598c22a55', '16b64cb6-65a9-4b3d-9cf9-15299f65e279', 'matrix', 'Questions 1 – 7', '', '<p data-path-to-node="3"><em data-path-to-node="3" data-index-in-node="136">Write the correct letter, <strong data-path-to-node="3" data-index-in-node="162">A, B, C</strong> or <strong data-path-to-node="3" data-index-in-node="173">D</strong>, in boxes 1-7 on your answer sheet.</em></p>
<p data-path-to-node="4"><strong data-path-to-node="4" data-index-in-node="0">NB</strong> <em data-path-to-node="4" data-index-in-node="3">You may use any letter more than once.</em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "It is in a quiet location.", "correctCategoryLetter": "A"}, {"itemText": "Furniture is provided.", "correctCategoryLetter": "C"}, {"itemText": "A washing machine is available for use.", "correctCategoryLetter": "C"}, {"itemText": "It is ready for occupation now.", "correctCategoryLetter": "A"}, {"itemText": "Secure private parking is available.", "correctCategoryLetter": "D"}, {"itemText": "It is near a sports facility.", "correctCategoryLetter": "B"}, {"itemText": "An appointment is needed to look at it.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. It is in a quiet location — {A} North Parkview</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“situated in a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">peaceful</strong> tree-lined street.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Peaceful” (yên bình) đồng nghĩa với “quiet” (yên tĩnh). Ngược lại, mẩu B nằm ở “busy Sydney Rd” (đường nhộn nhịp) nên không thể là đáp án.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. Furniture is provided — {C} Newport</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“An affordable, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"27\">fully-furnished</strong>, two-bedroom flat…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Fully-furnished” có nghĩa là đã được trang bị đầy đủ nội thất (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"76\">furniture is provided</strong>). Mẩu B ghi là “unfurnished” (không nội thất).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. A washing machine is available for use — {C} Newport</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“A <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"14\">shared coin-operated laundry (washing machine and dryer)</strong> is located in the basement.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mẩu C có sẵn máy giặt dùng chung chạy bằng tiền xu ở tầng hầm.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. It is ready for occupation now — {A} North Parkview</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Available <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"22\">immediately</strong>“</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Immediately” (ngay lập tức) đồng nghĩa với “now” (bây giờ). Các mẩu khác đều phải chờ (tháng sau, 2 tuần nữa, hoặc sang năm).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Secure private parking is available — {D} Karingal</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“Space for one vehicle in <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"37\">lock-up garage</strong> at rear.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Lock-up garage” (gara có khóa) chính là hình thức đỗ xe riêng tư và an toàn/bảo mật (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"98\">secure private parking</strong>). Mẩu C có đỗ xe nhưng là “on the street” (dưới lòng đường) nên không tính là private/secure.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. It is near a sports facility — {B} Brookvale</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Minutes from the park and <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"38\">swimming pool</strong>…”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bể bơi (swimming pool) được tính là một cơ sở hạ tầng thể thao (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"76\">sports facility</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. An appointment is needed to look at it — {D} Karingal</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“Viewing by <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"23\">prior arrangement only</strong>.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Prior arrangement” (sắp xếp trước) có nghĩa là bạn phải hẹn lịch trước (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"85\">appointment</strong>) thì mới được đến xem nhà. Các mẩu khác có giờ xem cố định (Saturday 11-12) hoặc chỉ cần đến đúng giờ (Just turn up).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('a85ee903-2354-4e9a-a812-66c3d1c9205b', '765df1f5-beee-4700-9bb0-26d5898969ab', 'matching', 'Questions 21-26', NULL, '<p>What is the student’s opinion on each of the following Environment Science modules?</p>
<p>Choose <strong>SIX </strong>correct answers, A-I, next to questions 21-26.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Environmental Science modules</strong></p>\n<p> </p>\n<p>Statistics for environmental research  {F was too basic to be useful}</p>\n<p> </p>\n<p>Sewage and drainage systems  {A was surprisingly interesting}</p>\n<p> </p>\n<p>Agriculture and food security {C included out-of-date materials}</p>\n<p> </p>\n<p>Sustainable energy  {D involved practical applications}</p>\n<p> </p>\n<p>Government policy  {I seemed too limited geographically}</p>\n<p> </p>\n<p>Water management  {G provided unnecessary detail}</p>", "answerOptions": [{"optionText": "A was surprisingly interesting"}, {"optionText": "B covered too many topics"}, {"optionText": "C included out-of-date materials"}, {"optionText": "D involved practical applications"}, {"optionText": "E supplied useful technical information"}, {"optionText": "F was too basic to be useful"}, {"optionText": "G provided unnecessary detail"}, {"optionText": "H was relevant to a topic in the news"}, {"optionText": "I seemed too limited geographically"}], "matchingItems": [{"questionPart": "Statistics for environmental research ", "correctAnswer": "F was too basic to be useful", "sectionContent": null}, {"questionPart": "Sewage and drainage systems ", "correctAnswer": "A was surprisingly interesting", "sectionContent": null}, {"questionPart": "Agriculture and food security ", "correctAnswer": "C included out-of-date materials", "sectionContent": null}, {"questionPart": "Sustainable energy ", "correctAnswer": "D involved practical applications", "sectionContent": null}, {"questionPart": "Government policy ", "correctAnswer": "I seemed too limited geographically", "sectionContent": null}, {"questionPart": "Water management ", "correctAnswer": "G provided unnecessary detail", "sectionContent": null}]}', 'null', '[{"content": "<h2>(Questions 21–26)</h2>\n<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear two students called Jamie and Martha discussing their Environmental Science course. First you have some time to look at questions twenty-one to twenty-six. Now listen carefully and answer questions twenty-one to twenty-six.</p>\n<p data-path-to-node=\"4\"><strong>Jamie:</strong> Hi Martha, do you have time to talk? We have to submit our evaluations of our course next week, and I thought it’d be useful to discuss what we both think.</p>\n<p data-path-to-node=\"5\"><strong>Martha:</strong> Good idea. That would help refresh my memory, especially about things we did in previous years.</p>\n<p data-path-to-node=\"6\"><strong>Jamie:</strong> I agree. So let’s talk about the modules we took. What about <span style=\"background-color: #f1c40f;\"><strong>(21) Statistics for environmental research</strong></span>? I’ve always been hopeless with numbers, so I thought that I’d learn a lot</p>\n<p data-path-to-node=\"6\"><strong>Martha:</strong> But you know it wasn’t at a high enough level for me.<span style=\"background-color: #f1c40f;\"> <strong>(21) (F: Was too basic to be useful)</strong>.</span>I actually had to do a lot of reading on my own.</p>\n<p data-path-to-node=\"7\"><strong>Jamie:</strong> Me too. I had to get an additional reading list from the tutor.</p>\n<p data-path-to-node=\"7\"><strong>Martha:</strong>  Now, <span style=\"background-color: #f1c40f;\"><strong>(22) Sewage and drainage systems</strong>.</span> I wasn’t looking forward to that one.</p>\n<p data-path-to-node=\"7\"><strong>Jamie: </strong>Not exactly a pleasant subject, but you know the module convinced me that it’s an essential topic to understand for both cities and rural environments.</p>\n<p data-path-to-node=\"8\"><strong>Martha:</strong> Right, and in the end, not a boring subject.</p>\n<p data-path-to-node=\"8\"><strong>Jamie:</strong> <span style=\"background-color: #f1c40f;\"><strong>(22) Not at all. It was quite a revelation (A: Was surprisingly interesting)</strong>.</span></p>\n<p data-path-to-node=\"9\"><strong>Martha:</strong> The module on <span style=\"background-color: #f1c40f;\"><strong>(23) Agriculture and food security</strong></span> could have been good.</p>\n<p data-path-to-node=\"9\"><strong>Jamie: </strong>but the assigned readings were only those ancient government publications.</p>\n<p data-path-to-node=\"9\"><strong>Martha:</strong> and the lecture notes clearly hadn’t been updated for years. <span style=\"background-color: #f1c40f;\"><strong>(23) (C: Included out-of-date materials)</strong>.</span></p>\n<p data-path-to-node=\"10\"><strong>Jamie:</strong> I know. What about the module on<span style=\"background-color: #f1c40f;\"> <strong>(24) Sustainable energy</strong></span>? I really got into the project we had to do to invent something functional. I devised a windmill to power my laptop.<span style=\"background-color: #f1c40f;\"> <strong>(24) (D: Involved practical applications)</strong></span>.</p>\n<p data-path-to-node=\"11\"><strong>Martha:</strong> Yep, the projects were great, so hands-on. Though the personal battery charger I built never really worked.</p>\n<p data-path-to-node=\"11\"> <strong>Jamie:</strong>Too bad! But I’m sure you learned a lot nonetheless.</p>\n<p data-path-to-node=\"12\"><strong>Martha:</strong> I did. And the <span style=\"background-color: #f1c40f;\"><strong>(25) Government policy</strong></span> module. I wish it had included policy in other countries. It was a bit inward-looking, I thought. Focused just on this country. <span style=\"background-color: #f1c40f;\"><strong>(25) (I: Seemed too limited geographically)</strong>.</span></p>\n<p data-path-to-node=\"13\"><strong>Martha:</strong> I mentioned that to the lecturer, but she said it was best to concentrate on one country in depth at first, .</p>\n<p data-path-to-node=\"14\"><strong>Jamie:</strong> Maybe and there was that module called <span style=\"background-color: #f1c40f;\"><strong>(26) Water management</strong>.</span> I must admit I got lost in the discussion about the issues of groundwater levels and flood risk management, which weren’t that essential. <span style=\"background-color: #f1c40f;\"><strong>(26) (G: Provided unnecessary detail)</strong>.</span></p>\n<p data-path-to-node=\"15\"><strong>Martha:</strong> You weren’t the only one.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('cb22534a-96b7-46be-a773-b92178b0bcc1', '5f88df1a-8a40-4ae9-a0c7-aaf964c06444', 'matching', 'Questions 14–18', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Historical reasons why interrupted sleep became uncommon"}, {"optionText": "ii Brain structures involved in sleep patterns"}, {"optionText": "iii Potential health issues related to sleep"}, {"optionText": "iv Famous cases in literature of sleep"}, {"optionText": "v An analysis of old documents to discover deep patterns"}, {"optionText": "vi Biological and environmental factors preventing people from falling asleep again"}, {"optionText": "vii Scientific evidence that divided sleep is a natural phenomenon"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>14. Paragraph A</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: vii. Scientific evidence that divided sleep is a natural phenomenon</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn A mô tả thí nghiệm khoa học của Thomas Wehr, chứng minh rằng mô hình ngủ chia làm hai giai đoạn (divided sleep) là mô hình tự nhiên (natural) của con người khi không bị ánh sáng nhân tạo chi phối.</p>\n</li>\n</ul>\n<p><strong>15. Paragraph B</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: v. An analysis of old documents to discover deep patterns</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn B nói về nghiên cứu của nhà sử học Roger Ekirch, người đã phân tích hơn 500 tài liệu lịch sử (diaries, court recorders, medical books&#8230;) để khám phá ra mô hình ngủ phân đoạn.</p>\n</li>\n</ul>\n<p><strong>16. Paragraph C</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: i. Historical reasons why interrupted sleep became uncommon</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn C giải thích sự biến mất của giấc ngủ chia đoạn, gắn liền với <strong>cải tiến ánh sáng đường phố</strong> (street and home lighting) và sự trỗi dậy của <strong>văn hóa quán cà phê</strong> (coffee houses), khiến việc thức khuya trở nên phổ biến.</p>\n</li>\n</ul>\n<p><strong>17. Paragraph D</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: vi. Biological and environmental factors preventing people from falling asleep again</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn D thảo luận về nguyên nhân của chứng mất ngủ giữa đêm (<strong>sleep maintenance insomnia</strong>) là do sự <strong>ưa thích tự nhiên</strong> của cơ thể đối với giấc ngủ chia đoạn (biological factor) và <strong>tiếp xúc kéo dài với ánh sáng nhân tạo</strong> (environmental factor).</p>\n</li>\n</ul>\n<p><strong>18. Paragraph E</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: iii. Potential health issues related to sleep</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn E tập trung vào tác động tâm lý của việc lo lắng về giấc ngủ (có thể làm tăng stress) và dẫn lời Russell Foster nói rằng <strong>hơn 30% vấn đề y tế</strong> (<strong>medical problems/health issues</strong>) có liên quan trực tiếp hoặc gián tiếp đến giấc ngủ.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('5de7d728-4cdf-4c54-aab0-de0e2d6299d5', '765df1f5-beee-4700-9bb0-26d5898969ab', 'checkbox', 'Questions 27–28', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>aspects of the course organisation did both Jamie and Martha like?</p>
', 'multiple-select', 'null', '[{"option": "the amount of reading", "correct": false}, {"option": "the flexibility in the length of the course", "correct": false}, {"option": "the convenience of choosing when take modules", "correct": false}, {"option": "the range of different modules offered", "correct": true}, {"option": "the relevance of the module content", "correct": true}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>(Questions 27–28)</strong></p>\n<p data-path-to-node=\"3\"><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions 27 to 30 on page six. Now listen and answer questions 27 to thirty.</p>\n<p data-path-to-node=\"5\"><strong>Jamie:</strong> Okay, I thought some aspects of the course organization were particularly helpful. Can we talk a bit about that?</p>\n<p data-path-to-node=\"6\"><strong>Martha:</strong> Of course. Actually, I was disappointed that I couldn’t take any module whenever I wanted.</p>\n<p data-path-to-node=\"6\"><strong>Jamie:</strong> That’s true, but <span style=\"background-color: #f1c40f;\"><strong>(27) the variety of modules on offer was a strong point (B)</strong></span>, and meant I managed to cover a lot of subjects.</p>\n<p data-path-to-node=\"7\"><strong>Martha:</strong> Me too, more than I expected.</p>\n<p data-path-to-node=\"7\"><strong>Jamie:</strong>I had wanted to finish the course early by doing an extra module each term, which would have been useful, but unfortunately, that wasn’t allowed.</p>\n<p data-path-to-node=\"7\"><strong>Martha:</strong>I had to wait to do some modules, which I found hard to schedule. And I think more assigned reading for the modules would have made the lectures easier to follow.</p>\n<p data-path-to-node=\"8\"><strong>Jamie:</strong> That would have been good, but I was pleased that the course organisers were able to provide modules focusing on <span style=\"background-color: #f1c40f;\"><strong>(28) real-life issues (D)</strong></span>, which we can apply later when looking for jobs.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('396b97e4-528c-48b5-a19b-f0852a103bfb', '765df1f5-beee-4700-9bb0-26d5898969ab', 'checkbox', 'Questions 29–30', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO</strong> suggestions for written assignment do Jamie and Martha agree to recommend to Dr Brown?</p>
', 'multiple_choice_many', 'null', '[{"option": "The time for choosing a topic should be changed.", "correct": true}, {"option": "The permitted word limit should be increased.", "correct": false}, {"option": "Discussions with fellow students should be arranged.", "correct": true}, {"option": "Face-to-face feedback sessions with the tutor should be scheduled.", "correct": false}, {"option": "Tutors should give more help in topic selection.", "correct": false}]', 'null', 'null', '[{"content": "<h2>(Questions 29–30)</h2>\n<p data-path-to-node=\"3\"><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions 27 to 30 on page six. Now listen and answer questions 27 to thirty.</p>\n<p data-path-to-node=\"4\"><em>(…đoạn hội thoại trước đó kết thúc bằng việc Jamie nói rằng anh ta muốn có thêm nhiều bài đọc hơn…)</em></p>\n<p data-path-to-node=\"5\"><strong>Martha:</strong> That would have been good, but I was pleased that the course organisers were able to provide modules focusing on real-life issues, which we can apply later when looking for jobs.</p>\n<p data-path-to-node=\"6\"><strong>Jamie:</strong> True, and I would have hated it if it had all been theory. What about the written paper we had to do for Dr Brown? Are there any things we could suggest to improve the way that’s handled?</p>\n<p data-path-to-node=\"7\"><strong>Martha:</strong> Well, I got lots of help from Dr Brown and his assistant in narrowing down what I wanted to write about. Yes, they stopped me from doing something too ambitious. But choosing a topic right at the beginning of the module was difficult. Maybe he could <span style=\"background-color: #f1c40f;\"><strong>(29) postpone the decision until halfway through the term</strong>.</span></p>\n<p data-path-to-node=\"8\"><strong>Jamie:</strong> Good idea. I was happy with the word limit for the assignment, though. Well, as usual, I could have written on and on, but the limit made me refine my thoughts, so it was okay in the end. I wish I could have had a session with Dr Brown after he’d marked my written paper. I know it would be time consuming, but it would have been really useful.</p>\n<p data-path-to-node=\"9\"><strong>Martha:</strong> Actually, I was satisfied with Dr Brown’s written feedback; it was amazingly detailed, so I don’t think I needed more. But I wish they could arrange sessions where students <span style=\"background-color: #f1c40f;\"><strong>(30) get together and help each other before submitting their written work</strong>.</span></p>\n<p data-path-to-node=\"10\"><strong>Jamie:</strong> Good idea! If they provided time for that, it would be quite convenient.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('c974d31f-3181-4204-bab1-678649706591', '28da66c7-6792-494b-9920-4aca673f271a', 'radio', 'Questions 21–24', NULL, '<p>Choose the correct letter, A, B or C.</p>
<p><span style="font-size: 12pt;"><strong>Pacific tapa cloth</strong></span></p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. the only tapa made today"}, {"content": "B. better quality than others"}, {"content": "C. put to a wider range of uses"}], "question": "Pacific tapa cloth is different from other types of tapa cloth because it is"}, {"correct": 1, "options": [{"content": "A. It is also a source of food"}, {"content": "B. It is not native to the Pacific"}, {"content": "C. It can grow in any environment"}], "question": "What does Helen say about the paper mulberry tree?"}, {"correct": 2, "options": [{"content": "A. They could not find the right trees in New Zealand"}, {"content": "B. They were introduced to other fabrics by the Europeans"}, {"content": "C. They found a better material for making fabric"}], "question": "Why did the Maori people of New Zealand stop making tapa?"}, {"correct": 0, "options": [{"content": "A. stuck together"}, {"content": "B. woven together"}, {"content": "C. sewn together"}], "question": "Large pieces of tapa are made from smaller pieces which are"}]', 'null', 'null', 'null', '[{"content": "<p>TUTOR: Come in, Helen. How can I help you?<br />\n🎧 Mời vào, Helen. Tôi có thể giúp gì cho em?</p>\n<p>HELEN: Well, I’m doing research for the anthropology assignment, and I was hoping to check a few details.<br />\n🎧 Em đang làm bài nghiên cứu nhân học và muốn kiểm tra vài chi tiết.</p>\n<p>TUTOR: Sure — you chose the topic of Pacific Island tapa cloth, didn’t you? What have you found out so far?<br />\n🎧 Được thôi — em chọn chủ đề về vải tapa của các đảo Thái Bình Dương đúng không? Vậy em tìm hiểu được gì rồi?</p>\n<p>HELEN: Well, I was going to introduce my assignment by saying that tapa cloth is a fabric made from bark — just the outer layer of the trees. It’s particularly common in the Pacific Islands, but not exclusive to them. In fact, many other peoples around the world have made high-quality cloth from bark.<br />\n🎧 Em định mở bài bằng cách nói rằng vải tapa được làm từ vỏ cây – cụ thể là lớp vỏ ngoài. Nó phổ biến ở các đảo Thái Bình Dương nhưng không phải duy nhất. Thực tế, nhiều nơi khác trên thế giới cũng từng làm loại vải vỏ cây chất lượng cao.</p>\n<p>HELEN: But (Question 21) what sets Pacific tapa apart is the incredible variety of roles it’s played in this region.<br />\n🎧 Nhưng điều khiến tapa ở Thái Bình Dương khác biệt là sự đa dạng trong công dụng (wider range of uses) mà nó đảm nhận trong khu vực này.</p>\n<p>TUTOR: Yes, nice introduction — though I think you could be more specific regarding dates.<br />\n🎧 Hay lắm, nhưng em nên cụ thể hơn về mốc thời gian.</p>\n<p>HELEN: Okay. So, what about the raw materials used?<br />\n🎧 Vâng, vậy còn nguyên liệu thì sao ạ?</p>\n<p>TUTOR: Well, tapa cloth is made from several species of tree. In the Pacific, the paper mulberry tree is most common — (Question 22) but it doesn’t thrive in all conditions. In fact, it wasn’t originally found in the islands but was carried in their canoes by the first migrants.<br />\n🎧 Vải tapa được làm từ nhiều loại cây khác nhau. Ở Thái Bình Dương, phổ biến nhất là cây dâu giấy (paper mulberry), nhưng nó không thể sinh trưởng ở mọi điều kiện. Thực ra, loài cây này không có nguồn gốc bản địa (not native) mà được người di cư đầu tiên mang theo bằng thuyền.</p>\n<p>TUTOR: Tapa is also made from the breadfruit tree, which is convenient because its fruit is a staple food. The paper mulberry tree is only grown for tapa making though.<br />\n🎧 Vải tapa cũng có thể làm từ cây sa kê, tiện lợi vì trái của nó là nguồn thực phẩm chính. Còn cây dâu giấy thì chỉ trồng để làm vải tapa thôi.</p>\n<p>TUTOR: Now what about the Maori people here in New Zealand?<br />\n🎧 Vậy còn người Maori ở New Zealand thì sao?</p>\n<p>HELEN: But the Maori don’t make tapa now.<br />\n🎧 Nhưng giờ người Maori không còn làm tapa nữa.</p>\n<p>TUTOR: That’s right, and you need to account for it. We know that when Maori migrated here from the other Pacific islands, they were prepared to make tapa because they brought the paper mulberry tree with them.<br />\n🎧 Đúng rồi, và em cần giải thích tại sao. Khi người Maori di cư từ các đảo khác sang đây, họ cũng mang theo cây dâu giấy để làm tapa.</p>\n<p>TUTOR: (Question 23) The thing was, after they’d been in New Zealand a bit, they found the flax plant, which is superior to tapa because it makes a stronger fabric.<br />\n🎧 Tuy nhiên, sau khi đến New Zealand, họ phát hiện ra cây lanh (flax) — loại nguyên liệu tốt hơn vì tạo ra vải bền hơn, nên họ đã dừng làm tapa.</p>\n<p>TUTOR: By the time Europeans arrived in the 18th century, Maori were making all their fabric from flax and had been for some time.<br />\n🎧 Khi người châu Âu đến vào thế kỷ 18, người Maori đã sử dụng hoàn toàn sợi lanh để dệt vải từ lâu.</p>\n<p>TUTOR: Okay, so with the production process itself — first, the inner bark is beaten with wooden hammers to soften the fibres. Then, (Question 24) the different pieces are glued together using an adhesive paste made from the arrowroot tuber.<br />\n🎧 Về quy trình sản xuất: trước tiên, lớp vỏ bên trong được đập bằng búa gỗ để làm mềm sợi. Sau đó, các mảnh vỏ được dán lại với nhau (stuck together) bằng hỗn hợp keo làm từ củ dong.</p>\n<p>TUTOR: This is the only way to make large pieces of cloth because bark strands are too fine to be woven, and stitching isn’t strong enough.<br />\n🎧 Đây là cách duy nhất để tạo thành tấm vải lớn, vì sợi vỏ cây quá mảnh để dệt, còn khâu thì không đủ chắc.</p>\n<p>✅ Questions 25–30<br />\nTUTOR: So now you need details about different countries — where would you start?<br />\n🎧 Giờ em cần nói cụ thể về từng quốc gia — em định bắt đầu ở đâu?</p>\n<p>HELEN: I think Samoa is the obvious place. It’s famous for its very fine cloth called siapo, which is hand-painted with representations of the ancestors. Still today, at the most profound events in life — such as births, funerals, weddings, and the investiture of chiefs — Samoans wear Siapo robes to add significance and meaning to the ceremony.<br />\n🎧 Em nghĩ nên bắt đầu với Samoa. Nơi đây nổi tiếng với loại vải tinh xảo tên siapo, được vẽ tay hình tổ tiên. Cho đến ngày nay, trong những dịp trọng đại như sinh nở, tang lễ, cưới hỏi hay lễ phong chức, người Samoa vẫn mặc siapo để thể hiện ý nghĩa tâm linh.<br />\n→ (Question 25) Function: C – spiritual</p>\n<p>TUTOR: Okay, then I could talk about Tonga.<br />\n🎧 Tốt. Còn Tonga thì sao?</p>\n<p>HELEN: It seems that the great innovation in Tonga has been developing a simple, coarse cloth which is quick and easy to make. This is suitable for all sorts of everyday functions around the house like bed covers, mosquito nets, and curtains.<br />\n🎧 Tại Tonga, điểm cải tiến nổi bật là họ phát triển loại vải thô, đơn giản, dễ làm — phù hợp cho các nhu cầu hàng ngày như chăn, màn hay rèm cửa.<br />\n→ (Question 26) Function: B – practical</p>\n<p>TUTOR: Good point. Now, what about Cook Islands tapa?<br />\n🎧 Ý hay. Thế còn vải tapa ở quần đảo Cook?</p>\n<p>HELEN: Well, the soil there is poor quality, so the breadfruit tree is often used. One type of thick cloth called tikoru was wrapped around the poles and used to mark the entrances to places of worship — so it was highly regarded in local culture.<br />\n🎧 Đất ở đó khá xấu nên họ thường dùng cây sa kê. Loại vải dày tên tikoru được quấn quanh cột để đánh dấu lối vào các nơi thờ cúng, vì thế nó mang giá trị tinh thần cao.<br />\n→ (Question 27) Function: C – spiritual</p>\n<p>TUTOR: You might mention Fiji as well. It’s interesting because tapa was actually used as a currency there — Fijians used to sail between the islands and exchange tapa for other commodities like canoes or pigs.<br />\n🎧 Em có thể nhắc tới Fiji nữa. Ở đó, tapa từng được dùng như tiền tệ — người dân trao đổi vải tapa lấy hàng hóa như thuyền hay heo.<br />\n→ (Question 28) Function: D – commercial</p>\n<p>HELEN: I know that in Tahiti the tapa cloth is different because the patterns are in colour, which is considered more valuable than the usual brown patterns.<br />\n🎧 Em biết ở Tahiti, vải tapa có hoa văn màu sắc — được xem là quý hơn loại nâu thông thường.</p>\n<p>TUTOR: You’re right about the Tahitians using coloured pigments, but they aren’t more valuable — the colours are only a decoration. People enjoy wearing bright robes, especially for dancing and competitive games — and do it just for fun.<br />\n🎧 Đúng là họ dùng màu sắc, nhưng chỉ để trang trí. Người dân thích mặc áo rực rỡ để nhảy múa và chơi trò giải trí, hoàn toàn vì vui thôi.<br />\n→ (Question 29) Function: A – recreational</p>\n<p>HELEN: The last place I was going to mention was Tikopia. Even today, it’s commonplace to see people wearing clothes made of tapa cloth. In many of the other islands, tapa only comes out on special occasions — but here, you see people working in the gardens wearing tapa.<br />\n🎧 Cuối cùng là đảo Tikopia. Đến nay, người dân vẫn mặc quần áo làm từ vải tapa hằng ngày. Trong khi ở các đảo khác chỉ dùng trong dịp đặc biệt, thì ở đây, họ vẫn mặc tapa để làm việc và sinh hoạt bình thường.<br />\n→ (Question 30) Function: B – practical</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('13606439-2ade-40e6-a069-a05ddea977a7', '54824b2d-cd17-4ecf-a386-a7b2b138299d', 'fillup', 'Questions 31-36', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>GRAPHICAL SYMBOL</strong></span></p>
<p><strong>‘Graphical symbol’</strong></p>
<p>– includes the logographs in Egyptian hieroglyphic writing and ancient Chinese pictograms</p>
<p>– found in Africa, the Americas, and Oceania</p>
<p>– still has something to do with {commercial} use today</p>
<p><strong>Ancient graphic writing systems</strong></p>
<p>– Researchers obtain a wide range of {knowledge} about past civilisations.</p>
<p>– Rosetta Stone was found in 1799 when members of Napoleon’s expedition got to Egypt.</p>
<p>– Frenchman Jean-Francois Champollion determined the phonetic values of the symbols in 1822.</p>
<p>– In those symbols, {lines} are used to depict various meanings.</p>
<p><strong>Camera obscura</strong></p>
<p>–  {Photography} helps people understand history better.</p>
<p>– Some charities will {advertise} many endangered species.</p>
<p>– A camera was tied to one {foot} of a bird.</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2>(Questions 31–36)</h2>\n<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a talk on the research of the graphical symbol. First you have some time to look at questions thirty one to forty. Now listen carefully and answer questions thirty-one to forty.</p>\n<p data-path-to-node=\"4\"><strong>Lecturer:</strong> Good morning everyone. Today I’m going to talk about the graphical symbol. A graphic symbol is a written symbol that is used to represent speech, such as those used in the Greek alphabet. The term graphic symbol encompasses anything from the logographs used in Egyptian hieroglyphic writing to ancient Chinese pictograms.</p>\n<p data-path-to-node=\"5\"><strong>Lecturer:</strong> Early symbols were based on pictographs and ideograms before they were developed into logographic writing systems. These systems are still in use in some non-literate cultures in Africa, the Americas, and Oceania. Indeed, elements of pictography are still found in modern Chinese characters, and it is often an interesting exercise to trace the origins of some Chinese characters.</p>\n<p data-path-to-node=\"6\"><strong>Lecturer:</strong> Pictographs remain in <span style=\"background-color: #f1c40f;\"><strong>(31) common commercial</strong></span> use today as signs, instructions, or statistical diagrams. Road signs and public toilet signs and even flat pack assembly instructions utilizing pictures are considered pictographic. Ancient graphic writing systems provide researchers with a wealth of <span style=\"background-color: #f1c40f;\"><strong>(32) knowledge</strong></span> about past civilizations.</p>\n<p data-path-to-node=\"7\"><strong>Lecturer:</strong> In seventeen ninety nine, one of the most important historical discoveries was made by accident when members of Napoleon’s expedition to Egypt found a stone in Rosetta that exhibited three different scripts. The stone, now known as the Rosetta Stone, was studied in significant depth by scholars and was first deciphered by Frenchman Jean-François Champollion in eighteen twenty-two. He was able to correctly determine the phonetic values of the symbols, and later research has confirmed his findings. In many of these symbols, <span style=\"background-color: #f1c40f;\"><strong>(33) Lines</strong></span> are used to portray a multitude of meanings, and knowledge and understanding of these Lines holds the key to comprehension of graphic writing systems.</p>\n<p data-path-to-node=\"8\"><strong>Lecturer:</strong> A key moment in the history of communication was the invention of the camera obscura, or camera. Although the concept can be traced back to the fifth century BC Chinese philosopher Mo Ti, the first photographic image was ultimately created in eighteen twenty six by Joseph Nicéphore Niépce. <span style=\"background-color: #f1c40f;\"><strong>(34) Photography</strong></span>, as it was later known, enables researchers to piece together and better understand history.</p>\n<p data-path-to-node=\"9\"><strong>Lecturer:</strong> Today photography forms a huge part of everyday life, and most publications contain a vast number of photographs. Photography is used in advertising and is now becoming a way to increase awareness of existing world issues. For example, Animal welfare charities are increasingly using photography to<span style=\"background-color: #f1c40f;\"> <strong>(35) advertise</strong></span> animals that are at high risk of endangerment. Charity workers are sometimes flown to far flung locations to document the suffering endured by high risk animals in an attempt to raise human awareness of their consumption activities and how they impact others.</p>\n<p data-path-to-node=\"10\"><strong>Lecturer:</strong> One recent high-profile campaign was undertaken by attaching a camera to the <span style=\"background-color: #f1c40f;\"><strong>(36) foot</strong> </span>of a bird in order to obtain photographs of the animals in their natural habitats and understand how often they come into contact with human waste.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('1e27e1fb-b940-4550-b6ef-8e57a85f1b2f', '28da66c7-6792-494b-9920-4aca673f271a', 'matrix', 'Questions 25–30', NULL, '<p>According to the speakers, what function has tapa cloth played in the following countries?<br />Write the correct letter, A, B, C or D, next to questions 25–30.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "Countries", "matrixItems": [{"itemText": "Samoa ", "correctCategoryLetter": "C"}, {"itemText": "Tonga ", "correctCategoryLetter": "B"}, {"itemText": "Cook Islands ", "correctCategoryLetter": "C"}, {"itemText": "Fiji ", "correctCategoryLetter": "D"}, {"itemText": "Tahiti ", "correctCategoryLetter": "A"}, {"itemText": "Tikopia ", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "recreational", "categoryLetter": "A"}, {"categoryText": "practical", "categoryLetter": "B"}, {"categoryText": "spiritual", "categoryLetter": "C"}, {"categoryText": "commercial", "categoryLetter": "D"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f8c0914f-966a-45c9-a199-6040dfd1a1b2', '54824b2d-cd17-4ecf-a386-a7b2b138299d', 'fillup', 'Questions 37-40', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p>More {objects} will be included in the future with the development of photography.</p>
<p>Companies would like to invest a lot to advertise in {newspapers}.</p>
<p>Designing appealing {packaging} is used as a way of effective branding.</p>
<p>Graphic writing systems are of great importance in the subject of {mathematics | math | maths}.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2>(Questions 37–40)</h2>\n<p data-path-to-node=\"3\"><strong>Lecturer:</strong> …One recent high profile campaign was undertaken by attaching a camera to the foot of a Bird in order to obtain photographs of the animals in their natural habitats and understand how often they come into contact with human waste.</p>\n<p data-path-to-node=\"4\"><strong>Lecturer:</strong> A soon-to-be-released documentary about the suffering of animals on Midway Island shows the full extent to which human consumption is harming animals thousands of miles away from us. As photography continues to progress, with the use of drones now becoming somewhat commonplace, we should expect more and more<span style=\"background-color: #f1c40f;\"> <strong>(37) objects</strong> </span>to be included in the future, expanding the horizon of photography ever further.</p>\n<p data-path-to-node=\"5\"><strong>Lecturer:</strong> Indeed, the downward pressure on traditional media prices means that media companies are being forced to get creative on how to make a profit. Many have found that the answer to this lies in advertising, and companies are now willing to devote a large portion of their budgets to advertising in <span style=\"background-color: #f1c40f;\"><strong>(38) newspapers</strong>.</span></p>\n<p data-path-to-node=\"6\"><strong>Lecturer:</strong> By the same token, marketing has become an essential part of a company’s business model, often meaning the success or failure of a company. As a result, much time and money has been pumped into the development of effective branding, with attractive<span style=\"background-color: #f1c40f;\"> <strong>(39) packaging</strong></span> playing a large role in this. However, many governments are now seen to be cracking down on marketing and packaging in an attempt to protect consumers from being misled. In particular, tobacco companies are now subject to ever-increasing regulation.For example, in the United Kingdom, legislation is soon to pass preventing any form of branding or differentiation on cigarette packaging in efforts to curb the harmful effects of smoking.</p>\n<p data-path-to-node=\"7\"><strong>Lecturer:</strong> Finally, one must not forget the fundamental role that graphic writing systems have had to play in <span style=\"background-color: #f1c40f;\"><strong>(40) mathematics</strong></span>. Graphs, icons, and diagrams often form the very basis of these branches of academia. Indeed, one needs to look no further than chemistry’s periodic table to see a perfect example of graphic writing systems in use today.</p>\n<p data-path-to-node=\"8\"><strong>Narrator:</strong> That is the end of Part Four. You now have one minute to check your answers to Part Four.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ddbf26e1-dc54-41e9-af30-c50a26021927', '5dc33733-64d5-43ac-b164-67239ee453ed', 'fillup', 'Questions 1-10', '<p>Complete the notes below</p>
<p>Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> for each answer.</p>
<p><strong>Caller record card</strong></p>
<p>Caller’s phone number: 03786 439 251</p>
<p>Caller’s name: Robert {Ridyard }</p>
<p>Address: {27 station road}, Moortown</p>
<p>Postcode: DP17 5HJ</p>
<p>Date of birth: {25th february}</p>
<p>Doctor’s name: Dr. Craven</p>
<p>Doctor’s address: Moortown Health Centre</p>
<p>Reason for call: Pain in his {lower} back</p>
<p>Previous history: Similar back problem in June last year<br><strong>Details of present problem:</strong></p>
<p>– Started {3 days} ago</p>
<p>– Got worse this {afternoon}</p>
<p>– No abdominal pain</p>
<p><strong>Possible cause: </strong>Lifting up a heavy {box}</p>
<p><strong>Treatment already applied:</strong></p>
<p>– Has applied heat</p>
<p>– Has taken {painkillers}</p>
<p><strong>Advice given:</strong></p>
<p>– Try using {ice}</p>
<p>– Go to doctor tomorrow</p>
<p>– Ask for information about {exercises}</p>', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a man with a problem with his back and a medical advisor. First you have some time to look at questions one to seven. Now listen carefully and answer questions one to seven.</p>\n<p data-path-to-node=\"4\"><strong>Advisor:</strong> Hello, this is Medical Help Direct, how can I help you?</p>\n<p data-path-to-node=\"5\"><strong>Robert:</strong> Oh hello, I’ve got a problem with my back, and with it being the middle of the night, I can’t go to the doctor, and I wonder if you can give me some advice.</p>\n<p data-path-to-node=\"6\"><strong>Advisor:</strong> Certainly, but first can I have your telephone number please? It’s 03786 439 251.</p>\n<p data-path-to-node=\"6\"><strong>Advisor:</strong> Okay, and if you could give me your first name please.</p>\n<p data-path-to-node=\"7\"><strong>Robert:</strong> Robert.</p>\n<p data-path-to-node=\"8\"><strong>Advisor:</strong> And your surname.</p>\n<p data-path-to-node=\"9\"><strong>Robert:</strong> <span style=\"background-color: #f1c40f;\"><strong>(1) Ridyard</strong></span>. That’s R-I-D-Y-A-R-D.</p>\n<p data-path-to-node=\"9\"><strong>Advisor:</strong>And now your address please.</p>\n<p data-path-to-node=\"10\"><strong>Robert:</strong> It’s<span style=\"background-color: #f1c40f;\"> <strong>(2) 27 Station Road.</strong></span></p>\n<p data-path-to-node=\"10\"><strong>Advisor:</strong> okay.</p>\n<p data-path-to-node=\"10\"><strong>Robert:</strong> Moortown.</p>\n<p data-path-to-node=\"11\"><strong>Robert:</strong> And do you need the postcode?</p>\n<p data-path-to-node=\"12\"><strong>Advisor:</strong> Yes please.</p>\n<p data-path-to-node=\"12\"><strong>Robert:</strong> DP17 5HJ.</p>\n<p data-path-to-node=\"13\"><strong>Advisor:</strong> And your date of birth.</p>\n<p data-path-to-node=\"14\"><strong>Robert:</strong> The <span style=\"background-color: #f1c40f;\"><strong>(3) 25th of February 1975</strong>.</span></p>\n<p data-path-to-node=\"15\"><strong>Advisor:</strong> Fine. Now I just need to take details of your doctor.</p>\n<p data-path-to-node=\"15\"><strong>Robert:</strong> She’s called Doctor Craven</p>\n<p data-path-to-node=\"15\"><strong>Advisor:</strong> and the surgery,</p>\n<p data-path-to-node=\"15\"><strong>Robert:</strong>it’s Moortown Health Centre.</p>\n<p data-path-to-node=\"15\"><strong>Advisor:</strong> Thanks. Now, can you tell me a bit more about what the problem is?</p>\n<p data-path-to-node=\"16\"><strong>Robert:</strong> Well, like I said, it’s my back.</p>\n<p data-path-to-node=\"17\"><strong>Advisor:</strong> Okay, can you tell me which part of the back?</p>\n<p data-path-to-node=\"18\"><strong>Robert:</strong> <span style=\"background-color: #f1c40f;\"><strong>(4) lower</strong>.</span></p>\n<p data-path-to-node=\"19\"><strong>Advisor:</strong> And have you had any problems with your back before?</p>\n<p data-path-to-node=\"20\"><strong>Robert:</strong> Yes, I had a bit of trouble last year in June I think, or was it July? No, we went on holiday at the beginning of July, and it had cleared up by then.</p>\n<p data-path-to-node=\"21\"><strong>Advisor:</strong> And when did it start this time? Has it just come on?</p>\n<p data-path-to-node=\"22\"><strong>Robert:</strong> No, I’ve had it, let’s see, since <span style=\"background-color: #f1c40f;\"><strong>(5) Monday</strong></span> so that’s <strong>three Days</strong> now, but it wasn’t too bad at first. I mean I could just about get around, though I couldn’t drive the car or anything. Then this <span style=\"background-color: #f1c40f;\"><strong>(6) afternoon</strong></span> the pain suddenly got so bad that I went to bed. I’ve been in bed since, but that hasn’t helped.</p>\n<p data-path-to-node=\"22\"><strong>Advisor:</strong> And do you have any pain elsewhere, in your stomach or abdomen for example?</p>\n<p data-path-to-node=\"23\"><strong>Robert:</strong> No.</p>\n<p data-path-to-node=\"25\"><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions seven to ten. Now listen and answer questions seven to ten.</p>\n<p data-path-to-node=\"26\"><strong>Advisor:</strong> Okay, now have you any idea what caused the problem?</p>\n<p data-path-to-node=\"27\"><strong>Robert:</strong> Well, I was tidying up my office, and I lifted a <span style=\"background-color: #f1c40f;\"><strong>(7) box</strong></span> up from the floor that was heavier than I thought, and I think that’s what did it.</p>\n<p data-path-to-node=\"28\"><strong>Advisor:</strong> Yes, it’s easily done, isn’t it? So you’re in bed now? Have you tried applying heat to the back?</p>\n<p data-path-to-node=\"29\"><strong>Robert:</strong> Yes, I’ve got a hot water bottle, that’s usually the first thing I try.</p>\n<p data-path-to-node=\"30\"><strong>Advisor:</strong> And have you taken any <span style=\"background-color: #f1c40f;\"><strong>(8) painkillers</strong></span>?</p>\n<p data-path-to-node=\"31\"><strong>Robert:</strong> Yes.</p>\n<p data-path-to-node=\"32\"><strong>Advisor:</strong> And other than that, you feel quite well?</p>\n<p data-path-to-node=\"33\"><strong>Robert:</strong> I do, yes.</p>\n<p data-path-to-node=\"34\"><strong>Advisor:</strong> Right, now I can’t diagnose or prescribe any medication, but I can offer you some advice. One thing you could do now is to see if<span style=\"background-color: #f1c40f;\"> <strong>(9) ice</strong> </span>makes any difference. That sometimes helps, but don’t put it directly onto your skin, wrap it up in a towel or something, and don’t leave it on for longer than twenty minutes.</p>\n<p data-path-to-node=\"35\"><strong>Robert:</strong> All right, I haven’t tried that before.</p>\n<p data-path-to-node=\"36\"><strong>Advisor:</strong> It can be useful sometimes. Now have you seen your doctor about this?</p>\n<p data-path-to-node=\"37\"><strong>Robert:</strong> No, I just thought, well, everyone has back pain, but I’ve never had it as bad as this before.</p>\n<p data-path-to-node=\"38\"><strong>Advisor:</strong> I think you should go and see your doctor tomorrow, and she may be able to give you something to help.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Robert:</strong> OK, I’ll do that. I’m actually feeling a bit better now.</p>\n<p data-path-to-node=\"38\"><strong>Advisor:</strong>Good.And you might get some advice from her about <span style=\"background-color: #f1c40f;\"><strong>(10) exercises</strong></span>. That’s often the best way of dealing with this sort of problem.</p>\n<p data-path-to-node=\"39\"><strong>Robert:</strong> Okay, I’ll ask her.</p>\n<p data-path-to-node=\"39\"><strong>Advisor:</strong>Right, now if you’re worried about anything before tomorrow, you can always phone back. Our lines are open twenty four hours.</p>\n<p data-path-to-node=\"40\"><strong>Robert:</strong> Thanks very much.</p>\n<p data-path-to-node=\"41\"><strong>Narrator:</strong> That is the end of Section One. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('d005c75b-141a-41ab-9010-51fbfd0de167', '6321cd8a-6075-4bfb-8cc9-0c8d0b6a4d26', 'radio', 'Questions 28-32', '', '<p data-path-to-node="3">Choose the correct letter, <strong data-path-to-node="3" data-index-in-node="27">A, B, C or D</strong>.</p>
<p data-path-to-node="4">Write the correct letter in boxes 28-32 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. It is a complex process to manage."}, {"option_text": "B. It does not necessarily result in improvements.B. It does not necessarily result in improvements."}, {"option_text": "C. It is more important than protecting the environment."}, {"option_text": "D. It does not take place at the same speed in every city."}], "question": "What does the writer say about economic growth in cities in the first paragraph?"}, {"correct": 2, "options": [{"option_text": "A. They are willing to offer tax incentives to business."}, {"option_text": "B. They make the needs of businesses in their city a priority."}, {"option_text": "C. They understand what makes their city better than other cities."}, {"option_text": "D. They consult with business advisers to identify growth prospects."}], "question": "According to the writer, what distinguishes the best city leader?"}, {"correct": 3, "options": [{"option_text": "A. indicating how clusters of companies change over time."}, {"option_text": "B. comparing the approaches to growth of different companies."}, {"option_text": "C. describing the impact a skilled workforce can have on a company’s success."}, {"option_text": "D. explaining the advantages of same sector companies being located close to each other."}], "question": "What is the writer doing in the third paragraph?"}, {"correct": 3, "options": [{"option_text": "A. It needs to identify what the potential risks are."}, {"option_text": "B. It should include stages for assessing progress."}, {"option_text": "C. It needs to take a long-term view of transportation issues."}, {"option_text": "D. It should balance the views of local people against broader priorities."}], "question": "Which of the following best summarises the writer’s attitude towards good city planning in the seventh paragraph?"}, {"correct": 2, "options": [{"option_text": "A. A limited number of cities have achieved this status."}, {"option_text": "B. It takes huge investment to improve residents'' quality of life."}, {"option_text": "C. There should be equal access to opportunities in these cities."}, {"option_text": "D. They become more important as the world''s population grows."}], "question": "What point is the writer making about great cities in the final paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. What does the writer say about economic growth in cities in the first paragraph? — {B} It does not necessarily result in improvements.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Economic growth, however, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"38\">does not automatically deliver a better quality of life</strong> for citizens, and can often harm the environment.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định tăng trưởng kinh tế không “tự động” mang lại chất lượng cuộc sống tốt hơn. Điều này đồng nghĩa với việc nó <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"138\">không nhất thiết dẫn đến những cải thiện</strong> (does not necessarily result in improvements).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. According to the writer, what distinguishes the best city leader? — {C} They understand what makes their city better than other cities.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Rather, their leaders’ vision for the city should be colored by a sound assessment of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"98\">where the city’s competitive advantages lie</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Competitive advantages” (lợi thế cạnh tranh) chính là những thứ làm cho thành phố đó tốt hơn hoặc đặc biệt hơn những nơi khác. Người lãnh đạo giỏi nhất là người hiểu rõ lợi thế này.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. What is the writer doing in the third paragraph? — {D} explaining the advantages of same sector companies being located close to each other.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Their <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"18\">physical proximity</strong> to one another will <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"57\">lower supply costs, improve R&amp;D collaboration, and assist the building of a skilled workforce</strong>…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 3 tập trung nói về “clusters” (các cụm công nghiệp). Việc các công ty cùng ngành ở gần nhau (physical proximity) mang lại nhiều lợi ích về chi phí, nghiên cứu và nhân lực. Đây chính là phần giải thích các ưu điểm (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"231\">advantages</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. Which of the following best summarises the writer’s attitude towards good city planning in the seventh paragraph? — {D} It should balance the views of local people against broader priorities.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Smart growth therefore requires a planning process that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"68\">combines the two</strong> [top-down and bottom-up].”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cho rằng quy hoạch thông minh cần kết hợp giữa:\n<ul data-path-to-node=\"11,1,1\">\n<li><strong data-path-to-node=\"11,1,1,0,0\" data-index-in-node=\"0\">Top-down</strong> (Từ trên xuống – chính quyền trung ương/vùng với các ưu tiên lớn hơn).</li>\n<li><strong data-path-to-node=\"11,1,1,1,0\" data-index-in-node=\"0\">Bottom-up</strong> (Từ dưới lên – đại diện cho concerns của cư dân địa phương).</li>\n<li>Kết hợp cả hai chính là sự cân bằng (<strong data-path-to-node=\"11,1,1,2,0\" data-index-in-node=\"37\">balance</strong>) giữa ý kiến người dân và các ưu tiên rộng lớn hơn.</li>\n</ul>\n</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">32. What point is the writer making about great cities in the final paragraph? — {C} There should be equal access to opportunities in these cities.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“Its benefits should be <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"35\">available to all</strong> of the city’s citizens… reducing inequalities and protecting the vulnerable… We have to <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"144\">look out for everyone</strong>.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh lợi ích của sự phát triển phải dành cho tất cả mọi người, giảm bất bình đẳng. Điều này tương ứng với việc <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"136\">tiếp cận cơ hội một cách bình đẳng</strong> (equal access to opportunities).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('9fe0b5fd-9b65-4e2a-9bd4-db51b6694bde', 'd1a5553a-a7c4-4e55-af53-0b431388ee92', 'radio', 'Questions 11–16', NULL, '<p>Choose the correct answer.</p>
<p><span style="font-size: 12pt;"><strong>MOVING OFFICE</strong></span></p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "to have more space"}, {"content": "to pay less rent"}, {"content": "be in a central location"}], "question": "What reason does the manager give for moving to a new office building?"}, {"correct": 1, "options": [{"content": "the air-conditioning system"}, {"content": "the amount of natural light"}, {"content": "the low level of noise"}], "question": "What is best about the new office building?"}, {"correct": 0, "options": [{"content": "after the sales conference"}, {"content": "after the end of the tax year"}, {"content": "after the annual holiday period"}], "question": "When will the office move take place?"}, {"correct": 1, "options": [{"content": "where to park"}, {"content": "places to eat"}, {"content": "public transport"}], "question": "what information about the new location is already on the company website?"}, {"correct": 0, "options": [{"content": "give details of damaged furniture"}, {"content": "throw away unnecessary papers"}, {"content": "take home personal items"}], "question": "What practical thing must staff do now?"}, {"correct": 1, "options": [{"content": "into packing boxes"}, {"content": "into grey plastic bags"}, {"content": "into new filing cabinets"}], "question": "Staff will need to put folders containing confidential details"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a manager talking to company employees about moving to a new office building. First you have some time to look at questions eleven to sixteen. Now listen carefully and answer questions eleven to sixteen.</p>\n<p data-path-to-node=\"5\"><strong>Manager:</strong> Thank you for coming to today’s meeting, everyone. I’d like to give you some information about moving to our new office building so that you know what the plans are. So first, let me explain why we’re moving. Even though we’ve taken on quite a few new employees over the last year, we still have plenty of space here. But the problem is where we are, but we’ve now found the perfect place in the <span style=\"background-color: #f1c40f;\"><strong>(11) City Centre</strong> <strong>(C: be in a central location)</strong></span>. Originally we chose this building in the suburbs because the rent was much cheaper, but our clients aren’t always keen on coming out here.</p>\n<p data-path-to-node=\"7\"><strong>Manager:</strong> I visited the new office last week, and I’m pretty sure that you’ll find the greatest advantage is the huge <span style=\"background-color: #f1c40f;\"><strong>(12) Windows</strong> <strong>(B: the amount of natural light)</strong></span>. I’m not sure we’ll need desk lamps at all. Of course, we’ll have everything checked out to make sure we can control the temperature of each office and we may have to put some room dividers in some offices so that you’re not disturbed by your colleagues’ conversations.</p>\n<p data-path-to-node=\"9\"><strong>Manager:</strong> We’ve just set a date for the move. The finance department wanted us to wait until after the end of the tax year, April, but we’ve decided to move earlier. As soon as the<span style=\"background-color: #f1c40f;\"> <strong>(13) sales conference is over in January</strong> <strong>(A: after the sales conference)</strong></span>, we’ll move. That’ll give us plenty of time to organize everything before you start taking your annual holidays. We’ve already put quite a bit of information about the move on the company website, like <span style=\"background-color: #f1c40f;\"><strong>(14) restaurants and cafes</strong></span> around the new office <strong>(B: places to eat)</strong>. But we’re still checking bus routes and things like that, so transport information will be up by next Monday. Another thing still to get confirmed is which car park we can use and how many people can use it.</p>\n<p data-path-to-node=\"11\"><strong>Manager:</strong> Okay, let’s move on to some practical things you have to do now. Don’t worry yet about taking home your photos and things like that, that can be sorted out much nearer the time, along with getting rid of any unwanted paperwork. We need to find out how many new desks and chairs to order so could you make a list of any of the ones you use that are scratched or <span style=\"background-color: #f1c40f;\"><strong>(15) broken</strong> <strong>(A: give details of damaged furniture)</strong></span>. Just one thing, all documents containing non-confidential information can go into the general packing boxes, but when it comes to documents containing confidential information, you’ll need to put these in special bags. You’ll be given <span style=\"background-color: #f1c40f;\"><strong>(16) Grey plastic ones</strong> </span>for this <strong>(B: into grey plastic bags)</strong>.So, one thing to do now is go through your filing cabinets and identify which folders are confidential.</p>\n<p data-path-to-node=\"14\"><strong>Narrator:</strong> Before you hear the rest of the talk, you have some time to look at questions seventeen to twenty on page four. Now listen and answer questions seventeen to twenty.</p>\n<p data-path-to-node=\"16\"><strong>Manager:</strong> Now to help you prepare for the move, I’d like to talk about lifting heavy things.You shouldn&#8217;t really have to do this because a removal company will be used, but you might want to move a box out of your way or something. It’s surprising how often people don’t remember to <span style=\"background-color: #f1c40f;\"><strong>(17) use the handles</strong></span> on the boxes (D: use handles), although they all have them. You’ve all had the leaflet explaining that you should keep your back straight and your head up when lifting, and it also tells you to stand with your feet firmly on the ground and a little bit apart. So I think that&#8217;s clear.But the leaflet emphasizes the importance of not <span style=\"background-color: #f1c40f;\"><strong>(18) twisting</strong></span> to the left or right once you’ve picked something up (C: don’t lean to one side). And if you’re like me, that’s easy to forget.</p>\n<p data-path-to-node=\"18\"><strong>Manager:</strong> I’d also like to talk about papers. If they’ve been stored for a long time, they may have mold and fungus and as soon as you start moving them, the fungus gets disturbed. As you know, you can’t open the windows in this building, but I suggest you use the <span style=\"background-color: #f1c40f;\"><strong>(19) gloves</strong></span> that we’ll provide (C: wear gloves). We’ll also get some face masks, but we’ve been advised that these shouldn’t be necessary. What you should do is <span style=\"background-color: #f1c40f;\"><strong>(20) drink one or two liters of water</strong> </span>a day <strong>(D: drink plenty of water)</strong>. That’s essential. Often the best time to do this sort of work is after your afternoon break so that you can leave the building soon afterwards. Now, are there any questions?</p>\n<p data-path-to-node=\"20\"><strong>Narrator:</strong> That is the end of Section Two. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('0aa6c7f4-d8d4-4582-a845-05afc0ecf70d', 'd1a5553a-a7c4-4e55-af53-0b431388ee92', 'checkbox', 'Questions 17–18', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>things do people often forget when lifting heavy things?</p>
', 'multiple_choice_many', 'null', '[{"option": "A keep your head up", "correct": false}, {"option": "B don’t bend your back", "correct": false}, {"option": "C don’t lean to one side", "correct": true}, {"option": "D use handles", "correct": true}, {"option": "E stand with feet apart", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('93cb8781-f40b-4120-9fb9-bab7547bcc19', '6321cd8a-6075-4bfb-8cc9-0c8d0b6a4d26', 'matrix', 'Questions 33-36', '', '<p>Write the correct letter, <strong data-path-to-node="3" data-index-in-node="156">A-G</strong>, in boxes 33-36 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Cities", "matrixItems": [{"itemText": "It aims to offer more accommodation without expanding the size of the city.", "correctCategoryLetter": "F"}, {"itemText": "It set up a facility to improve the skills of potential workers.", "correctCategoryLetter": "D"}, {"itemText": "It has a policy that encourages residents to cut the amount of waste they produce.", "correctCategoryLetter": "G"}, {"itemText": "The expansion of the IT sector here was rapid.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Atanta", "categoryLetter": "A"}, {"categoryText": "London", "categoryLetter": "B"}, {"categoryText": "Dubai", "categoryLetter": "C"}, {"categoryText": "West Point", "categoryLetter": "D"}, {"categoryText": "Bogota", "categoryLetter": "E"}, {"categoryText": "New York", "categoryLetter": "F"}, {"categoryText": "Zurich", "categoryLetter": "G"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">33. It aims to offer more accommodation without expanding the size of the city. — {F} New York</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"21\">New York</strong> encourages the refurbishment of existing housing units, sometimes <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"96\">splitting them into smaller units</strong> or studios and <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"145\">building on rooftops</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc chia nhỏ căn hộ cũ hoặc xây thêm trên sân thượng (building on rooftops) giúp tăng số lượng chỗ ở (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"115\">more accommodation</strong>) mà không cần chiếm thêm đất mới hay mở rộng diện tích bề mặt của thành phố (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"211\">without expanding the size</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">34. It set up a facility to improve the skills of potential workers. — {D} West Point</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">West Point</strong>… has spent $145 million on <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"61\">building a job-training facility</strong> for <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"98\">would-be automotive workers</strong>…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Job-training facility” (cơ sở đào tạo nghề) tương ứng với “facility to improve skills”. “Would-be workers” tương ứng với “potential workers” (những công nhân tiềm năng).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">35. It has a policy that encourages residents to cut the amount of waste they produce. — {G} Zurich</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 10):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"22\">Zurich</strong>… uses pricing to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"48\">reduce the volume of household rubbish</strong>, requiring residents to dispose of rubbish in garbage bags that cost around $4.25 each.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bằng cách đánh phí cao vào túi đựng rác, Zurich đã khuyến khích người dân cắt giảm (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">cut/reduce</strong>) lượng rác thải (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"124\">waste/rubbish</strong>) mà họ thải ra.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">36. The expansion of the IT sector here was rapid. — {B} London</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">London</strong>… succeeded in forming a new <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"58\">high-tech cluster</strong>… Within just <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"91\">three years</strong>… the number of digital and creative companies in the cluster grew from <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"176\">11 to over 300</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “High-tech cluster” (cụm công nghệ cao) đại diện cho “IT sector”. Việc tăng từ 11 lên 300 công ty chỉ trong vòng 3 năm là một sự mở rộng cực kỳ nhanh chóng (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"169\">rapid expansion</strong>).</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('9a0c15e8-6515-412b-9569-cc87235283e7', '8f4a1835-3939-4a03-bca6-d322336006fe', 'matching', 'Questions 27–33', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Write the correct number, <strong>i-viii</strong>, in boxes 27-33.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. A negative reaction to receiving flowers"}, {"optionText": "ii. Some surprisingly strong responses to flowers"}, {"optionText": "iii. A mutually beneficial relationship?"}, {"optionText": "iv. Becoming more open about personal matters"}, {"optionText": "v. Some common social functions of flowers"}, {"optionText": "vi. Sensory appeal versus practical purpose of flowers"}, {"optionText": " vii. Bridging the gap between strangers in an enclosed space"}, {"optionText": "viii. An imperfect theory"}], "matchingItems": null}', 'null', '[{"content": "<p>27. Paragraph 1 → v. Some common social functions of flowers<br />\n(Đoạn 1: “Why do people give flowers? To offer condolence&#8230; to express gratitude&#8230; to ask for forgiveness&#8230; few objects provoke such a universal response.”)<br />\n→ Đoạn mở bài liệt kê những mục đích xã hội phổ biến của việc tặng hoa – như chia buồn, cảm ơn, xin lỗi, và cách hoa gắn liền với cảm xúc con người.<br />\n→ Đáp án: v</p>\n<p>28. Paragraph 2 → iv. Becoming more open about personal matters<br />\n(Đoạn 2: “&#8230; women receiving flowers were assessed as displaying a much more positive mood&#8230; After receiving flowers, participants were more willing to answer questions concerning their social circle and intimate relationships.”)<br />\n→ Nghiên cứu chỉ ra rằng hoa giúp con người cởi mở hơn về cảm xúc và các mối quan hệ cá nhân.<br />\n→ Đáp án: iv</p>\n<p>29. Paragraph 3 → vii. Bridging the gap between strangers in an enclosed space<br />\n(Đoạn 3: “&#8230; inside an elevator&#8230; both men and women presented with flowers were more likely to smile, to stand closer and to initiate conversation.”)<br />\n→ Khi nhận hoa trong thang máy – một không gian kín – người lạ trở nên gần gũi và thân thiện hơn.<br />\n→ Đáp án: vii</p>\n<p>30. Paragraph 4 → ii. Some surprisingly strong responses to flowers<br />\n(Đoạn 4: “&#8230; some participants produced such extraordinary emotional displays&#8230; Subjects gave spontaneous hugs and kisses to the people who delivered the flowers&#8230;”)<br />\n→ Nghiên cứu cho thấy con người phản ứng rất mạnh mẽ và xúc động khi nhận hoa.<br />\n→ Đáp án: ii</p>\n<p>31. Paragraph 5 → viii. An imperfect theory<br />\n(Đoạn 5: “&#8230; the flaw in this argument is that the showy flowers which humans seem to find most visually attractive are generally found on those plants which yield no edible products.”)<br />\n→ Đoạn này bàn về lý thuyết tiến hóa của việc yêu thích hoa nhưng chỉ ra điểm sai trong giả thuyết này.<br />\n→ Đáp án: viii</p>\n<p>32. Paragraph 6 → vi. Sensory appeal versus practical purpose of flowers<br />\n(Đoạn 6: “&#8230; the various physical attributes of flowers combine to directly affect our emotions&#8230; these preferences have long been separated from their primary evolutionary use.”)<br />\n→ So sánh giá trị cảm xúc – màu sắc, mùi hương, hình dáng – với mục đích sinh học ban đầu của hoa.<br />\n→ Đáp án: vi</p>\n<p>33. Paragraph 7 → iii. A mutually beneficial relationship?<br />\n(Đoạn 7: “&#8230; flowers may have actually evolved to exploit their peculiar impact on humans&#8230; co-evolution&#8230; Flowers may be the plant equivalent of ‘companion animals’.”)<br />\n→ Tác giả gợi ý rằng con người và hoa có thể đã cùng tiến hóa, mang lại lợi ích cho cả hai phía.<br />\n→ Đáp án: iii</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('9f192f8f-4941-48a9-b228-9b034a9518c2', 'd1a5553a-a7c4-4e55-af53-0b431388ee92', 'checkbox', 'Questions 19–20', NULL, '<p>Choose <strong>TWO </strong>correct answers</p>
<p>Which <strong>TWO </strong>things should staff do when moving papers?</p>
', 'multiple_choice_many', 'null', '[{"option": "A wear a face mask", "correct": false}, {"option": "B open windows", "correct": false}, {"option": "C wear gloves", "correct": true}, {"option": "D take frequent breaks", "correct": false}, {"option": "E drink plenty of water", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('714159fb-d31f-4f2d-ae70-c5ad4a8cf8cf', '6321cd8a-6075-4bfb-8cc9-0c8d0b6a4d26', 'fillup', 'Questions 37-40', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong data-path-to-node="10" data-index-in-node="0">Economic and environmental considerations</strong></span></p>
<p>In order for the leaders of a city to achieve smart growth, they need to integrate economic and environmental considerations. A large amount of the {pollution} in the atmosphere is generated by cities. It is caused primarily by energy use in {offices} and people’s homes and by transportation. For instance, {congestion} on a city’s streets not only has an impact on business but it also raises the level of greenhouse gases, which affects people’s {health} .</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">37. A large amount of the {pollution} in the atmosphere is generated by cities.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Already, cities produce 70 percent of global <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"66\">air pollution</strong>, largely from energy consumption…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A large amount” tương ứng với con số “70 percent”. Thứ mà các thành phố tạo ra nhiều nhất trong khí quyển chính là sự ô nhiễm (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"140\">pollution</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38. It is caused primarily by energy use in {offices} and people’s homes and by transportation.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…largely from energy consumption in <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"59\">houses and offices</strong> and from <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"87\">transportation</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Primarily” tương ứng với “largely”. Nguồn gây ô nhiễm đến từ việc tiêu thụ năng lượng tại nhà ở (houses/homes) và văn phòng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"138\">offices</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">39. For instance, {congestion} on a city’s streets not only has an impact on business…</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Congestion</strong> in a city, for example, <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"56\">raises the cost of doing business</strong>…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “For instance” tương ứng với “for example”. “Impact on business” tương ứng với “raises the cost of doing business”. Tình trạng gây ra vấn đề này trên đường phố chính là sự tắc nghẽn giao thông (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"206\">congestion</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">40. …but it also raises the level of greenhouse gases, which affects people’s {health}.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…while the pollution it generates <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"57\">threatens citizens’ health</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Affects” (ảnh hưởng) tương ứng với “threatens” (đe dọa). Thứ bị ảnh hưởng trực tiếp bởi sự ô nhiễm và khí nhà kính ở đây chính là sức khỏe (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"153\">health</strong>) của người dân.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('79d3f0a9-3933-40e2-a41d-8659c2e87d37', 'e6d8ad6d-b6f3-4cfc-95af-ca0d652f1c64', 'radio', 'Questions 21–26', NULL, '<p>Choose the correct answer.</p>
<p><span style="font-size: 12pt;"><strong>Organising a debate</strong></span><br /><span style="font-size: 12pt;"><strong> </strong></span></p>
', 'multiple-choice', '[{"correct": 2, "options": [{"content": "She has attended debates in other departments."}, {"content": "She organised debates while at secondary school."}, {"content": "She has talked about debating with a friend."}], "question": "Why is Fiona keen to organise a debate?"}, {"correct": 0, "options": [{"content": "help students to form opinions."}, {"content": "improve students'' listening skills."}, {"content": "develop students'' self-confidence."}], "question": "Fiona says that an advantage of debating is that it can"}, {"correct": 1, "options": [{"content": "Daniel and Fiona will ask the lecturer to choose one from a list."}, {"content": "The other students will select one of Daniel and Fiona'' suggestions."}, {"content": "Daniel and Fiona will collect suggestions from the other students."}], "question": "How will the debate topic be selected"}, {"correct": 0, "options": [{"content": "have a topic that really involves them."}, {"content": "plan their speech carefully."}, {"content": "be given positions to defend."}], "question": "Daniel and Fiona think one key to a successful debate is for students to"}, {"correct": 0, "options": [{"content": "give everyone a chance to speak."}, {"content": "help students with less confidence."}, {"content": "share out the preparation required."}], "question": "Daniel thinks it would be good for the students to be in two teams because it would"}, {"correct": 0, "options": [{"content": "A make comments on students’ written work"}, {"content": "B help Daniel and Fiona to write a report"}, {"content": "C set the students an essay on a different topic"}], "question": "What does the lecturer agree to do after the debate?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong>Narrator:</strong> You will hear two students called Daniel and Martha discussing their psychology course with a tutor. First you have some time to look at questions twenty-one to twenty-six. Now listen carefully and answer questions twenty-one to twenty-six.</p>\n<p data-path-to-node=\"5\"><strong>Tutor:</strong> Right, now you wanted to organize a formal discussion of some sort in the class, is that right Daniel?</p>\n<p data-path-to-node=\"6\"><strong>Daniel:</strong> Yes, we thought it would be really good to end our psychology course with a formal debate, you know where there’s a statement and people argue for or against it.</p>\n<p data-path-to-node=\"7\"><strong>Tutor:</strong> Good idea. Where did the enthusiasm come from? Have either of you organized debates before?</p>\n<p data-path-to-node=\"8\"><strong>Martha:</strong> Fiona? No, but one of my friends did in his last year at secondary school and <span style=\"background-color: #f1c40f;\"><strong>(21) he says he got a lot out of doing It (C: She has talked about debating with a friend)</strong></span>.And I know they have debates in lots of other departments here at the university.</p>\n<p data-path-to-node=\"9\"><strong>Tutor:</strong>I see. So what do you think the students—you and the others—would get out of this?</p>\n<p data-path-to-node=\"10\"><strong>Daniel:</strong> Well, a debate will encourage people to study all sides of the subject matter, and I also think <span style=\"background-color: #f1c40f;\"><strong>(22) listening to other people’s ideas can have a focusing effect on your own (A: help students to form opinions)</strong>.</span>Sometimes you kind of don&#8217;t know what you truly believe until you hear something you disagree with.</p>\n<p data-path-to-node=\"11\"><strong>Tutor:</strong> Okay. What about the topic for the debate?</p>\n<p data-path-to-node=\"12\"><strong>Martha:</strong> We’ve got three to choose from.We&#8217;ll show you in a minute to check they&#8217;re OK. At first we thought we&#8217;d ask the other students to suggest something, but we were afraid we&#8217;d get 30 different topics. So instead, we brainstormed some, just the two of us, we made a short list, and <span style=\"background-color: #f1c40f;\"><strong>(23) we’ll get them to vote for the one they like best (B: The other students will select one of Daniel and Fiona’s suggestions)</strong>.</span></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Tutor:</strong> Right.</p>\n<p data-path-to-node=\"12\"><strong>Martha:</strong>But the thing is, if people don&#8217;t know how debates work, they could feel at a disadvantage. I mean, it wouldn&#8217;t affect their grades or anything, but it could put them off.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Daniel:</strong> So we thought we should have a meeting beforehand to make sure everyone&#8217;s clear about what&#8217;s involved in a debate and how to prepare for it.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Tutor:</strong> I think that&#8217;s a good idea.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Daniel:</strong>And we thought we could establish some key points of a successful debate there—like that debates are effective methods for considering an issue, and that you need to understand both sides of an argument in order to s upport one side effectively.</p>\n<p data-path-to-node=\"13\"><strong>Tutor:</strong>Hmm</p>\n<p data-path-to-node=\"13\"> <strong data-path-to-node=\"12\" data-index-in-node=\"0\">Daniel:</strong>We think it’ll be best if we can use an issue that the students <span style=\"background-color: #f1c40f;\"><strong>(24) already have strong opinions about (A: have a topic that really involves them)</strong>.</span></p>\n<p data-path-to-node=\"13\"><strong>Tutor:</strong>Then some people will be happy to speak in support of it and others to oppose it. Right, what else do you want to do at the meeting?</p>\n<p data-path-to-node=\"13\"><strong><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Daniel:</strong></strong> Well, we&#8217;ve got to think about how people will do the background research for the debate. We could organize everyone into two teams; that should save time for the main speakers. They won&#8217;t have to do it on their own. And we&#8217;ll need to decide on some rules,<strong><span style=\"background-color: #f1c40f;\">(25) like how long each person speaks for(A: give everyone a chance to speak.)</span></strong>, and to select a chair for the debate—someone who&#8217;s really confident.</p>\n<p data-path-to-node=\"16\"><strong>Tutor:</strong> Fine. Now I think you should have some sort of follow up to the debate after it’s over. I’d like you to get everyone to write a short essay focusing on what they gained from participating in it. And in turn, that can feed into the work we&#8217;ve been doing on learning and motivation.But would you be willing to read them and <span style=\"background-color: #f1c40f;\"><strong>(26) report back (A: make comments on students’ written work)</strong></span>, I mean give some feedback on them?</p>\n<p data-path-to-node=\"17\"><strong>Daniel:</strong> I wouldn’t have made the suggestion if I wasn’t. Thanks.</p>\n<p data-path-to-node=\"20\"><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions twenty-seven to thirty. Now listen and answer questions twenty-seven to thirty.</p>\n<p data-path-to-node=\"21\"><strong>Tutor:</strong> Okay, now let’s think a bit more about the meeting. You need to decide exactly how you’ll introduce the students to different features of a debate.</p>\n<p data-path-to-node=\"22\"><strong>Martha:</strong> Well,first of all, we need to inform everyone about what actually happens at a debate—the procedures and so on. We could talk about that and write the main information on the board, or instead of that, we could make a summary of the main stages and <span style=\"background-color: #f1c40f;\"><strong>(27) hand that out (B: give a handout of key points)</strong></span>, then talk it through.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Tutor:</strong> Yes, okay, that&#8217;s better.</p>\n<p data-path-to-node=\"23\"><strong>Daniel:</strong>Okay but we do need to talk about body language as well.</p>\n<p data-path-to-node=\"24\"><strong>Martha:</strong>Yes, that&#8217;s a very important tool<strong>.</strong> I’ve got an interesting article on that with some good diagrams of techniques for things like eye contact. <span style=\"background-color: #f1c40f;\"><strong>(28) I’ll make some copies for you to give out (D: provide a photocopy of an article)</strong>.</span></p>\n<p data-path-to-node=\"25\"><strong>Daniel:</strong> Great. Then we need to think about where people will find the information on the debate topic.So they&#8217;ll need to know where to look for the information. We could compile a list of sources—textbooks and articles and so on.</p>\n<p data-path-to-node=\"26\"><strong>Martha:</strong> We could, but couldn’t people offer their own suggestions and advice on that at the meeting instead? <span style=\"background-color: #f1c40f;\"><strong>(29) (A: ask for suggestion)</strong></span></p>\n<p data-path-to-node=\"27\"><strong>Daniel:</strong> Yes, get everyone involved! Right.What about preparation for asking and answering questions? We could try to demonstrate that, but I&#8217;m not sure how.</p>\n<p data-path-to-node=\"28\"><strong>Martha:</strong> Maybe we could <span style=\"background-color: #f1c40f;\"><strong>(30) put up a list of points on the board (C: write on the board)</strong>,</span> then discuss them.</p>\n<p data-path-to-node=\"29\"><strong>Daniel:</strong> Yes, that sounds better. Thanks.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Tutor:</strong> OK, well let&#8217;s meet up again&#8230;</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('05bb34cc-0d6f-4faf-aa3e-adbc9af6ae7a', 'e6d8ad6d-b6f3-4cfc-95af-ca0d652f1c64', 'matching', 'Questions 27–30', NULL, '<p>What will Daniel and Fiona do at the meeting to help students with debate?</p>
<p>Choose <strong>FOUR </strong>answers from the box, A-F.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Aspects of a debate</strong></p>\n<p> </p>\n<p>understanding debating procedures {B give a handout of key points}</p>\n<p> </p>\n<p>using body language {D provide a photocopy of an article}</p>\n<p> </p>\n<p>accessing resources {A ask for suggestion}</p>\n<p> </p>\n<p>asking and answering questions {C write on the board}</p>", "answerOptions": [{"optionText": "A ask for suggestion"}, {"optionText": "B give a handout of key points"}, {"optionText": "C write on the board"}, {"optionText": "D provide a photocopy of an article"}, {"optionText": "E recommend a textbook"}, {"optionText": "F give a demonstration"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f64134f8-185c-4ef5-8f23-fc2a35ae9604', '5f88df1a-8a40-4ae9-a0c7-aaf964c06444', 'matrix', 'Questions 19–23', '<p>Look at the following statements and the list of researchers below. </p>
<p>Match each statement with the correct researcher, A-E</p>
<p><em><strong>NB </strong>you may use any letter more than once.</em></p>
', '<p>Look at the following statements and the list of researchers below.</p>
<p>Match each statement with the correct researcher, A-E</p>
<p><em><strong>NB </strong>you may use any letter more than once.</em></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "In certain historical periods, the threat of criminal danger led to segmented sleep", "correctCategoryLetter": "C"}, {"itemText": "Physicians should learn more about treating people with sleeping difficulties.", "correctCategoryLetter": "E"}, {"itemText": "Historically, when people experienced interrupted sleep, they used the waking period at night for different activities", "correctCategoryLetter": "B"}, {"itemText": "Technological changes in Europe made people more likely to sleep throughout the night.", "correctCategoryLetter": "B"}, {"itemText": "The belief that humans should have a long continuous sleep can be psychologically harmful", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Thomas Wehr", "categoryLetter": "A"}, {"categoryText": "Roger Ekirch", "categoryLetter": "B"}, {"categoryText": "Craig Koslofsky", "categoryLetter": "C"}, {"categoryText": "Gregg Jacobs", "categoryLetter": "D"}, {"categoryText": "Russell Foster", "categoryLetter": "E"}]}', '[{"content": "<p><strong>19. In certain historical periods, the threat of criminal danger led to segmented sleep.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: C</strong> (Craig Koslofsky)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) Craig Koslofsky giải thích rằng <strong>&#8220;Associations with night before the 17th century were not good&#8221;</strong> và đường phố bị tội phạm chiếm đóng (<strong>&#8220;populated by thieves or worse&#8221;</strong>).</p>\n</li>\n</ul>\n<p><strong>20. Physicians should learn more about treating people with sleeping difficulties.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: E</strong> (Russell Foster)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn E) Russell Foster nói rằng <strong>&#8220;sleep has been ignored in medical training, and there are very few countries where sleep is studied,&#8221;</strong> và cảm thấy điều này cần phải thay đổi (<strong>&#8220;He feels this needs to change&#8221;</strong>).</p>\n</li>\n</ul>\n<p><strong>21. Historically, when people experienced interrupted sleep, they used the waking period at night for different activities.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: B</strong> (Roger Ekirch)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) Ekirch mô tả hoạt động giữa hai giấc ngủ: <strong>&#8220;read or wrote&#8221;</strong>, <strong>&#8220;think about and attempt to analyse their dreams&#8221;</strong>.</p>\n</li>\n</ul>\n<p><strong>22. Technological changes in Europe made people more likely to sleep throughout the night.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: B</strong> (Roger Ekirch)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn C) Ekirch <strong>&#8220;attributes the initial shift to improvements in street and home lighting&#8221;</strong>. Ánh sáng (technological change) đã khiến thời gian nghỉ ngơi giảm xuống.</p>\n</li>\n</ul>\n<p><strong>23. The belief that humans should have a long continuous sleep can be psychologically harmful.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: D</strong> (Gregg Jacobs)</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn E) Gregg Jacobs nói rằng <strong>&#8220;If it makes people who wake up in the night anxious, as this anxiety can itself discourage sleep&#8221;</strong>. Niềm tin này gây lo lắng (psychologically harmful).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('59239776-19dc-44b7-9835-8a9276fb97d5', '2b2420b8-99cf-4002-a1e3-9a2e6dff3a82', 'radio', 'Questions 21–24', NULL, '<p>Choose the correct letter, A, B or C.</p>
<p><span style="font-size: 12pt;"><strong>Pacific tapa cloth</strong></span></p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. the only tapa made today"}, {"content": "B. better quality than others"}, {"content": "C. put to a wider range of uses"}], "question": "Pacific tapa cloth is different from other types of tapa cloth because it is"}, {"correct": 1, "options": [{"content": "A. It is also a source of food"}, {"content": "B. It is not native to the Pacific"}, {"content": "C. It can grow in any environment"}], "question": "What does Helen say about the paper mulberry tree?"}, {"correct": 2, "options": [{"content": "A. They could not find the right trees in New Zealand"}, {"content": "B. They were introduced to other fabrics by the Europeans"}, {"content": "C. They found a better material for making fabric"}], "question": "Why did the Maori people of New Zealand stop making tapa?"}, {"correct": 0, "options": [{"content": "A. stuck together"}, {"content": "B. woven together"}, {"content": "C. sewn together"}], "question": "Large pieces of tapa are made from smaller pieces which are"}]', 'null', 'null', 'null', '[{"content": "<p>TUTOR: Come in, Helen. How can I help you?<br />\n🎧 Mời vào, Helen. Tôi có thể giúp gì cho em?</p>\n<p>HELEN: Well, I’m doing research for the anthropology assignment, and I was hoping to check a few details.<br />\n🎧 Em đang làm bài nghiên cứu nhân học và muốn kiểm tra vài chi tiết.</p>\n<p>TUTOR: Sure — you chose the topic of Pacific Island tapa cloth, didn’t you? What have you found out so far?<br />\n🎧 Được thôi — em chọn chủ đề về vải tapa của các đảo Thái Bình Dương đúng không? Vậy em tìm hiểu được gì rồi?</p>\n<p>HELEN: Well, I was going to introduce my assignment by saying that tapa cloth is a fabric made from bark — just the outer layer of the trees. It’s particularly common in the Pacific Islands, but not exclusive to them. In fact, many other peoples around the world have made high-quality cloth from bark.<br />\n🎧 Em định mở bài bằng cách nói rằng vải tapa được làm từ vỏ cây – cụ thể là lớp vỏ ngoài. Nó phổ biến ở các đảo Thái Bình Dương nhưng không phải duy nhất. Thực tế, nhiều nơi khác trên thế giới cũng từng làm loại vải vỏ cây chất lượng cao.</p>\n<p>HELEN: But (Question 21) what sets Pacific tapa apart is the incredible variety of roles it’s played in this region.<br />\n🎧 Nhưng điều khiến tapa ở Thái Bình Dương khác biệt là sự đa dạng trong công dụng (wider range of uses) mà nó đảm nhận trong khu vực này.</p>\n<p>TUTOR: Yes, nice introduction — though I think you could be more specific regarding dates.<br />\n🎧 Hay lắm, nhưng em nên cụ thể hơn về mốc thời gian.</p>\n<p>HELEN: Okay. So, what about the raw materials used?<br />\n🎧 Vâng, vậy còn nguyên liệu thì sao ạ?</p>\n<p>TUTOR: Well, tapa cloth is made from several species of tree. In the Pacific, the paper mulberry tree is most common — (Question 22) but it doesn’t thrive in all conditions. In fact, it wasn’t originally found in the islands but was carried in their canoes by the first migrants.<br />\n🎧 Vải tapa được làm từ nhiều loại cây khác nhau. Ở Thái Bình Dương, phổ biến nhất là cây dâu giấy (paper mulberry), nhưng nó không thể sinh trưởng ở mọi điều kiện. Thực ra, loài cây này không có nguồn gốc bản địa (not native) mà được người di cư đầu tiên mang theo bằng thuyền.</p>\n<p>TUTOR: Tapa is also made from the breadfruit tree, which is convenient because its fruit is a staple food. The paper mulberry tree is only grown for tapa making though.<br />\n🎧 Vải tapa cũng có thể làm từ cây sa kê, tiện lợi vì trái của nó là nguồn thực phẩm chính. Còn cây dâu giấy thì chỉ trồng để làm vải tapa thôi.</p>\n<p>TUTOR: Now what about the Maori people here in New Zealand?<br />\n🎧 Vậy còn người Maori ở New Zealand thì sao?</p>\n<p>HELEN: But the Maori don’t make tapa now.<br />\n🎧 Nhưng giờ người Maori không còn làm tapa nữa.</p>\n<p>TUTOR: That’s right, and you need to account for it. We know that when Maori migrated here from the other Pacific islands, they were prepared to make tapa because they brought the paper mulberry tree with them.<br />\n🎧 Đúng rồi, và em cần giải thích tại sao. Khi người Maori di cư từ các đảo khác sang đây, họ cũng mang theo cây dâu giấy để làm tapa.</p>\n<p>TUTOR: (Question 23) The thing was, after they’d been in New Zealand a bit, they found the flax plant, which is superior to tapa because it makes a stronger fabric.<br />\n🎧 Tuy nhiên, sau khi đến New Zealand, họ phát hiện ra cây lanh (flax) — loại nguyên liệu tốt hơn vì tạo ra vải bền hơn, nên họ đã dừng làm tapa.</p>\n<p>TUTOR: By the time Europeans arrived in the 18th century, Maori were making all their fabric from flax and had been for some time.<br />\n🎧 Khi người châu Âu đến vào thế kỷ 18, người Maori đã sử dụng hoàn toàn sợi lanh để dệt vải từ lâu.</p>\n<p>TUTOR: Okay, so with the production process itself — first, the inner bark is beaten with wooden hammers to soften the fibres. Then, (Question 24) the different pieces are glued together using an adhesive paste made from the arrowroot tuber.<br />\n🎧 Về quy trình sản xuất: trước tiên, lớp vỏ bên trong được đập bằng búa gỗ để làm mềm sợi. Sau đó, các mảnh vỏ được dán lại với nhau (stuck together) bằng hỗn hợp keo làm từ củ dong.</p>\n<p>TUTOR: This is the only way to make large pieces of cloth because bark strands are too fine to be woven, and stitching isn’t strong enough.<br />\n🎧 Đây là cách duy nhất để tạo thành tấm vải lớn, vì sợi vỏ cây quá mảnh để dệt, còn khâu thì không đủ chắc.</p>\n<p>✅ Questions 25–30<br />\nTUTOR: So now you need details about different countries — where would you start?<br />\n🎧 Giờ em cần nói cụ thể về từng quốc gia — em định bắt đầu ở đâu?</p>\n<p>HELEN: I think Samoa is the obvious place. It’s famous for its very fine cloth called siapo, which is hand-painted with representations of the ancestors. Still today, at the most profound events in life — such as births, funerals, weddings, and the investiture of chiefs — Samoans wear Siapo robes to add significance and meaning to the ceremony.<br />\n🎧 Em nghĩ nên bắt đầu với Samoa. Nơi đây nổi tiếng với loại vải tinh xảo tên siapo, được vẽ tay hình tổ tiên. Cho đến ngày nay, trong những dịp trọng đại như sinh nở, tang lễ, cưới hỏi hay lễ phong chức, người Samoa vẫn mặc siapo để thể hiện ý nghĩa tâm linh.<br />\n→ (Question 25) Function: C – spiritual</p>\n<p>TUTOR: Okay, then I could talk about Tonga.<br />\n🎧 Tốt. Còn Tonga thì sao?</p>\n<p>HELEN: It seems that the great innovation in Tonga has been developing a simple, coarse cloth which is quick and easy to make. This is suitable for all sorts of everyday functions around the house like bed covers, mosquito nets, and curtains.<br />\n🎧 Tại Tonga, điểm cải tiến nổi bật là họ phát triển loại vải thô, đơn giản, dễ làm — phù hợp cho các nhu cầu hàng ngày như chăn, màn hay rèm cửa.<br />\n→ (Question 26) Function: B – practical</p>\n<p>TUTOR: Good point. Now, what about Cook Islands tapa?<br />\n🎧 Ý hay. Thế còn vải tapa ở quần đảo Cook?</p>\n<p>HELEN: Well, the soil there is poor quality, so the breadfruit tree is often used. One type of thick cloth called tikoru was wrapped around the poles and used to mark the entrances to places of worship — so it was highly regarded in local culture.<br />\n🎧 Đất ở đó khá xấu nên họ thường dùng cây sa kê. Loại vải dày tên tikoru được quấn quanh cột để đánh dấu lối vào các nơi thờ cúng, vì thế nó mang giá trị tinh thần cao.<br />\n→ (Question 27) Function: C – spiritual</p>\n<p>TUTOR: You might mention Fiji as well. It’s interesting because tapa was actually used as a currency there — Fijians used to sail between the islands and exchange tapa for other commodities like canoes or pigs.<br />\n🎧 Em có thể nhắc tới Fiji nữa. Ở đó, tapa từng được dùng như tiền tệ — người dân trao đổi vải tapa lấy hàng hóa như thuyền hay heo.<br />\n→ (Question 28) Function: D – commercial</p>\n<p>HELEN: I know that in Tahiti the tapa cloth is different because the patterns are in colour, which is considered more valuable than the usual brown patterns.<br />\n🎧 Em biết ở Tahiti, vải tapa có hoa văn màu sắc — được xem là quý hơn loại nâu thông thường.</p>\n<p>TUTOR: You’re right about the Tahitians using coloured pigments, but they aren’t more valuable — the colours are only a decoration. People enjoy wearing bright robes, especially for dancing and competitive games — and do it just for fun.<br />\n🎧 Đúng là họ dùng màu sắc, nhưng chỉ để trang trí. Người dân thích mặc áo rực rỡ để nhảy múa và chơi trò giải trí, hoàn toàn vì vui thôi.<br />\n→ (Question 29) Function: A – recreational</p>\n<p>HELEN: The last place I was going to mention was Tikopia. Even today, it’s commonplace to see people wearing clothes made of tapa cloth. In many of the other islands, tapa only comes out on special occasions — but here, you see people working in the gardens wearing tapa.<br />\n🎧 Cuối cùng là đảo Tikopia. Đến nay, người dân vẫn mặc quần áo làm từ vải tapa hằng ngày. Trong khi ở các đảo khác chỉ dùng trong dịp đặc biệt, thì ở đây, họ vẫn mặc tapa để làm việc và sinh hoạt bình thường.<br />\n→ (Question 30) Function: B – practical</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('5d03babe-26d2-482f-bbea-9e19606a4237', 'bd92b44d-406e-41b0-bc5f-c0418a5ff2d3', 'radio', 'Questions 15 - 24', '', '<p data-path-to-node="5,0,0">Choose<strong data-path-to-node="5,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="5,1,0" data-index-in-node="0">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="5,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "All of the staff have overseas teaching experience"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "All modules are of equal length"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Students are encouraged to take holidays in the two-week breaks between modules"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Courses may have very different timetables"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You can still obtain an attendance certificate if you have been absent through illness"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Permission is required for students to bring guests into the restaurant"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The coffee lounge is closed in the evenings"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Groups of 20 or more can make reservations to dine at the restaurant on public holidays"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Guests may use the swimming pool"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Students are unable to enter the Institute after 8.30pm"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. All of the staff have overseas teaching experience. — {FALSE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“It has a highly-trained and experienced teaching staff. <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"68\">Many</strong> of whom have taught overseas.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"24\">nhiều người (many)</strong> từng dạy ở nước ngoài, trong khi câu hỏi nói <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"88\">tất cả (all)</strong>. Sự mâu thuẫn giữa “nhiều” và “tất cả” dẫn đến đáp án là False.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. All modules are of equal length. — {TRUE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Percil Training Institute provides courses in <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"58\">ten-week modules</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản khẳng định các học phần (modules) kéo dài 10 tuần. Điều này đồng nghĩa với việc chúng có độ dài bằng nhau.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Students are encouraged to take holidays in the two-week breaks between modules. — {FALSE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“…since project or assignments are set for completion in these periods, <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"85\">it is not possible to take vacations during this time</strong>.”</em></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì có bài tập/dự án phải hoàn thành trong 2 tuần nghỉ giữa các học phần, nên sinh viên <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"99\">không thể đi nghỉ lễ</strong>. Câu hỏi nói “được khuyến khích đi nghỉ” là trái ngược hoàn toàn.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. Courses may have very different timetables. — {TRUE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“Since each course has <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"34\">varying needs</strong> there are <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"58\">not necessarily any set hours</strong> for classes across all programmes.”</em></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Varying needs” và không có giờ cố định cho tất cả các chương trình chứng tỏ thời khóa biểu của các khóa học có thể rất khác nhau.</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. You can still obtain an attendance certificate if you have been absent through illness. — {FALSE}</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“Legitimate reasons for non-attendance (e.g. illness)… In this case, an <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"85\">achievement certificate only</strong> will be issued.”</em></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nếu nghỉ do ốm đau và có bằng chứng, bạn <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"53\">chỉ</strong> được cấp chứng chỉ hoàn thành (achievement certificate), nghĩa là bạn <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"127\">không</strong> được cấp chứng chỉ chuyên cần (attendance certificate).</li>\n</ul>\n<p><strong data-path-to-node=\"15\" data-index-in-node=\"0\">20. Permission is required for students to bring guests into the restaurant. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Phần “Facilities” nói về việc đặt chỗ nhà hàng và các nhóm khách.</li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc không hề đề cập đến việc sinh viên có cần xin phép (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"72\">permission</strong>) để dẫn khách vào nhà hàng hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"17\" data-index-in-node=\"0\">21. The coffee lounge is closed in the evenings. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc nói thời gian mở cửa được in dưới thời khóa biểu và nó thường đóng vào ngày lễ.</li>\n<li><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Không có thông tin cụ thể về việc nó có đóng cửa vào buổi tối hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"19\" data-index-in-node=\"0\">22. Groups of 20 or more can make reservations to dine at the restaurant on public holidays. — {TRUE}</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"11\">“However a group booking may be made for the restaurant… provided that there is a <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"95\">minimum of 20 people</strong> in the group [on public holidays].”</em></li>\n<li><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Minimum of 20” khớp với “20 or more”, và việc cho phép “group booking” khớp với “make reservations”.</li>\n</ul>\n<p><strong data-path-to-node=\"21\" data-index-in-node=\"0\">23. Guests may use the swimming pool. — {TRUE}</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"22,0,0\" data-index-in-node=\"12\">Guests</strong> of Percil students are <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"42\">welcome to use the swimming pool</strong> but not the gymnasium areas.”</em></li>\n<li><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản khẳng định rõ ràng khách được chào đón sử dụng bể bơi.</li>\n</ul>\n<p><strong data-path-to-node=\"23\" data-index-in-node=\"0\">24. Students are unable to enter the Institute after 8.30pm. — {FALSE}</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"24,0,0\" data-index-in-node=\"11\">“After 8.30 pm the front doors… are locked. If you need to gain access… please <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"94\">contact the caretaker</strong> by pressing the doorbell… If you are admitted… you will be required to show your student card.”</em></li>\n<li><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói sinh viên “không thể vào” (unable to enter), nhưng bài đọc chỉ dẫn cách để vào (nhấn chuông gọi người quản lý và trình thẻ). Vậy sinh viên <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"163\">vẫn có thể vào được</strong>.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('13abb259-d94f-43fa-bba5-af51933e61fb', '8f4a1835-3939-4a03-bca6-d322336006fe', 'matrix', 'Questions 34-37', NULL, '<p>Classify the following statements as referring to:</p>
<p>Choose the correct letter, A, B, or C, in boxes 34-37.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "The study focused on participants’ short-term reaction to receiving flowers.", "correctCategoryLetter": "B"}, {"itemText": "Participants were deliberately misled as to the aim of the study.", "correctCategoryLetter": "A"}, {"itemText": "Receiving flowers had a notable effect on participants’ mental capacities.", "correctCategoryLetter": "C"}, {"itemText": "Male and female responses were more uniform than expected.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "the first study", "categoryLetter": "A"}, {"categoryText": "the second study", "categoryLetter": "B"}, {"categoryText": "the third study", "categoryLetter": "C"}]}', '[{"content": "<p>34. The study focused on participants’ short-term reaction to receiving flowers → B: the second study<br />\n(Đoạn 3: “&#8230; participants being handed single flowers, or no gift at all, in a constrained and stressful situation—inside an elevator.”)<br />\n→ Mục tiêu của nghiên cứu thứ hai là quan sát phản ứng tức thời (short-term reaction) của người tham gia khi nhận hoa trong một tình huống xã hội ngắn và căng thẳng.<br />\n→ Đáp án: B – the second study</p>\n<p>35. Participants were deliberately misled as to the aim of the study → A: the first study<br />\n(Đoạn 2: “The women were unaware that the study was about the effect of gifts on their emotions. They were told that it was a study about their daily moods&#8230;”)<br />\n→ Những người tham gia không được biết mục tiêu thật của nghiên cứu — tức là họ bị dẫn dắt sai lệch một cách có chủ ý.<br />\n→ Đáp án: A – the first study</p>\n<p>36. Receiving flowers had a notable effect on participants’ mental capacities → C: the third study<br />\n(Đoạn 4: “&#8230; found not only a profound elevation of mood but also reliable improvements in other measures of cognitive function, like memory.”)<br />\n→ Nghiên cứu thứ ba cho thấy hoa không chỉ nâng cao tâm trạng mà còn cải thiện khả năng nhận thức (mental capacities) như trí nhớ.<br />\n→ Đáp án: C – the third study</p>\n<p>37. Male and female responses were more uniform than expected → B: the second study<br />\n(Đoạn 3: “Contrary to expectations regarding gender differences, both men and women presented with flowers were more likely to smile, to stand closer and to initiate conversation.”)<br />\n→ Trái với dự đoán ban đầu, phản ứng của nam và nữ tương tự nhau hơn mong đợi → thể hiện sự đồng nhất trong phản ứng giới tính.<br />\n→ Đáp án: B – the second study</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('d4a41a3b-f3e1-4814-8064-7208278c3652', 'fc1f7158-b09a-4c10-bce6-33a78e879d0c', 'fillup', 'Questions 30-40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Geography – 331 Field Trip</strong></span></p>
<p><strong>The James Bay Road</strong></p>
<p>– At the starting point of the road, everyone must stop for {registration}.</p>
<p>– For safety reasons, there are {telephones}  on the highway.</p>
<p><strong>Radisson Research Centre</strong></p>
<p>– The Centre works with other institutes to research the region’s {ecology}.</p>
<p>– Security is the responsibility of Hydro Quebec.</p>
<p>– Lectures will discuss the effect of {insects} on the land.</p>
<p>– Outpost stations gather and publish research related to variations in the {climate}.</p>
<p><strong>The Trans-Taiga Road</strong></p>
<p>– The road is unpaved.</p>
<p>– Breakdowns are serious as car {repairs} are expensive.</p>
<p>– At hydro stations, engineers will discuss hydro production and the impact of rainfall.</p>
<p><strong>The Taiga</strong></p>
<p>– There are not many types of {plant} , but a good range of wildlife.</p>
<p>– The area known as Muskeg is dangerous as it has hidden {pools}.</p>
<p>– Photographs of birds should be taken for future {documentation}.</p>
<p>– Water samples will be checked for {pollution}.</p>', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a geography professor telling his class about an upcoming field trip to the far North of Quebec in Canada. First you have some time to look at questions thirty-one to forty. Now listen carefully and answer questions thirty-one to forty.</p>\n<p data-path-to-node=\"4\"><strong>Professor:</strong> Good morning. Next week is the Geography 331 field trip to the far North of Quebec. Today I’ll discuss your trip and your tasks. As you know you will be close to the Arctic Circle. You’re going to travel up the James Bay Road through a region that is very remote and uninhabited yet very beautiful.</p>\n<h3>The James Bay Road</h3>\n<p data-path-to-node=\"7\"><strong>Professor:</strong> The highway is six hundred and twenty kilometers long, but it’s fully paved for the entire length. Where the highway begins, there is a roadside office where you must stop. The road is remote, so your <span style=\"background-color: #f1c40f;\"><strong>(31) registration</strong> </span>is very important in case of an emergency.The office is staffed 24 hours per day, seven days per week. You have to sign in to go up the road and sign out upon your return. For additional safety, at different places along the highway,<span style=\"background-color: #f1c40f;\"> <strong>(32) telephones</strong> </span>have been installed, which connect with staff in the office. Remember there is no mobile service in this remote area.</p>\n<h3>Radisson Research Centre</h3>\n<p data-path-to-node=\"10\"><strong>Professor:</strong> The first work of your field trip is at the end of the James Bay Road in Radisson, a small town of only 300 inhabitants.You will stay at Radisson Research Centre, which works with various universities and Hydro Quebec to carry out studies into the<span style=\"background-color: #f1c40f;\"> </span><strong><span style=\"background-color: #f1c40f;\">(33) ecology</span> </strong>of the region.Because the research center and the road exist as a result of the development of hydroelectricity complexes in northern Quebec, Hydro Quebec is responsible for all emergency assistance and security of all visitors. Your first few days at the centre will be spent attending lectures about their past research. You will hear that they have paid particular attention to any disturbance to the land caused by <span style=\"background-color: #f1c40f;\"><strong>(34) insects</strong></span>. After that you will visit the various outpost stations.There are three of them, and when you visit them,you will be able to observe how data on the varying patterns of the <span style=\"background-color: #f1c40f;\"><strong>(35) climate</strong></span> is collected and published for scientific research.</p>\n<h3>The Trans-Taiga Road</h3>\n<p data-path-to-node=\"13\"><strong>Professor:</strong> The second part of your field trip is back down the James Bay Road to the Trans-Taiga Road, which is the northernmost continuous unpaved road in eastern North America. In fact, it&#8217;s very uneven gravel, so drivers have to be very careful.Hydro Quebec cautions that driving over rocks on the rough road may cause severe damage to the car. Any breakdown is serious as car <span style=\"background-color: #f1c40f;\"><strong>(36) repairs</strong></span> are costly.Along the way, you will be stopping at two hydroelectric generating stations, each on a different river. There you will meet with engineers who will explain and demonstrate how rainfall has an impact on producing electric energy.</p>\n<h3>The Taiga</h3>\n<p data-path-to-node=\"16\"><strong>Professor:</strong> Your last two days of the trip will be spent camping out in the Taiga on the Canadian Shield.Taiga is the Russian term for a type of forest. You’ll find the region is relatively poor in the number of <span style=\"background-color: #f1c40f;\"><strong>(37) plant</strong></span> species, yet there is a great variety of wildlife that can be seen. You’ll go to an area that once had forest fires, and you&#8217;ll see how the landscape has naturally small rocky hills which confine the lower wetlands.These low lying areas are called muskeg, which is made up of slowly decomposing plants. It is not safe to walk on it as it has <strong><span style=\"background-color: #f1c40f;\">(38) pools</span> </strong>hidden that are not easily seen, so keep to the rocks<strong>.</strong>. The muskeg is home to many small birds and waterfowl; in fact, there are at least 60 varieties, so keep your waterproof digital cameras handy so you can take plenty of pictures. Then we will have <span style=\"background-color: #f1c40f;\"><strong>(39) documentation</strong></span> of the existing waterfowl as some are becoming extinct. Water is a problem in this area, so you’ll also be collecting test tubes of water to bring back to our research lab for analysis. It needs to be monitored for <span style=\"background-color: #f1c40f;\"><strong>(40) pollution</strong></span>.that may be caused by rainfall coming from the south.</p>\n<p data-path-to-node=\"18\"><strong>Narrator:</strong> That is the end of Part Four. You now have one minute to check your answers to Part Four.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ac44ddf1-6bfa-4113-b6bd-fcfb8c90112e', '2b2420b8-99cf-4002-a1e3-9a2e6dff3a82', 'matrix', 'Questions 25–30', NULL, '<p>According to the speakers, what function has tapa cloth played in the following countries?<br />
Write the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>, next to questions 25–30.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "Samoa ", "correctCategoryLetter": "C"}, {"itemText": "Tonga ", "correctCategoryLetter": "B"}, {"itemText": "Cook Islands ", "correctCategoryLetter": "C"}, {"itemText": "Fiji ", "correctCategoryLetter": "D"}, {"itemText": "Tahiti ", "correctCategoryLetter": "A"}, {"itemText": "Tikopia ", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "recreational", "categoryLetter": "A"}, {"categoryText": "practical", "categoryLetter": "B"}, {"categoryText": "spiritual", "categoryLetter": "C"}, {"categoryText": "commercial", "categoryLetter": "D"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('c8740867-c438-4779-9c9c-95944e64a5e7', '5f88df1a-8a40-4ae9-a0c7-aaf964c06444', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Historical patterns of interrupted sleep</strong></p>
<p>Historical evidence seems to show that humans had common sleep patterns which were quite unlike today’s eight hours of unbroken sleep each night. People habitually went to bed early, soon after {sunset} slept for a while, then woke up for a few hours of activity or perhaps to consider, for example, the meaning of {dreams} There was little else to do at home in the dark, since what little means of lighting they had, such as using candles, was costly. In 16th-century Europe, people tended to stay at home at night because they feared {thieves} on large unit city. Once urban street lighting improved, night life in cities became popular, and recreational spots, like coffee houses came to be considered fashionable. Consequently, sleeping patterns also began to change.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>24. People habitually went to bed early, soon after sunset&#8230;</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>sunset</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) Mô hình ngủ chia đoạn có &#8220;a first sleep which began <strong>not long following sunset</strong>.&#8221;</p>\n</li>\n</ul>\n<p><strong>25. &#8230;perhaps to consider, for example, the meaning of dreams&#8230;</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>dreams</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) &#8220;&#8230;people used the time that they were awake between periods of sleep to think about and attempt to analyse their <strong>dreams</strong>.&#8221;</p>\n</li>\n</ul>\n<p><strong>26. In 16th-century Europe, people tended to stay at home at night because they feared thieves&#8230;</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>thieves</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) &#8220;the streets of cities and towns at night were often populated by <strong>thieves</strong> or worse.&#8221;</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('32a19829-607b-4c60-88c6-a4c1da7fcf77', '8f4a1835-3939-4a03-bca6-d322336006fe', 'fillup', 'Questions 38-40', '<p>Complete the summary of paragraph E below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from paragraph E for each answer.</p>
<p>Write your answers in boxes 38-40 on your answer sheet.</p>
<p style="text-align: center;"><strong>A possible explanation for the appeal of flowers</strong></p>
<p>It has been suggested that our intense response to flowers originates in prehistoric times. The presence of flowers might indicate a potential source of {food} in a particular location, and primitive humans would search for such signs when looking for a suitable site to raise their {children}. The interpretation of these signs was essential for the survival of our ancestors. However, the problem with this idea is that the plants producing the most attractive flowers do not usually have fruit which is {edible}.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>38. The presence of flowers might indicate a potential source of {food} → FOOD<br />\n(Đoạn 5: “&#8230; when these clues in our environment could mean the difference between starvation and survival. We may have become hardwired to respond positively to flowers because, for early man, finding them in a particular location predicted future food supplies&#8230;”)<br />\n→ Giả thuyết tiến hoá cho rằng con người nguyên thuỷ phản ứng mạnh với hoa vì nơi có hoa thường dự báo có nguồn thức ăn.<br />\n→ Đáp án: food</p>\n<p>39. &#8230; when looking for a suitable site to raise their {children} → CHILDREN<br />\n(Đoạn 5: “&#8230; and possibly a better place to rear children.”)<br />\n→ Ngoài ra, hoa còn gợi ý về môi trường an toàn, thuận lợi để nuôi dưỡng con cái.<br />\n→ Đáp án: children</p>\n<p>40. &#8230; but the plants producing the most attractive flowers do not usually have fruit which is {edible} → EDIBLE<br />\n(Đoạn 5: “&#8230; the showy flowers which humans seem to find most visually attractive are generally found on those plants which yield no edible products.”)<br />\n→ Điểm yếu của giả thuyết là: những loài hoa đẹp nhất lại thường không sinh ra quả có thể ăn được.<br />\n→ Đáp án: edible</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('69daa39e-9967-43b7-8202-e8b8d7146cfa', '05e635d8-e209-4fcb-ac52-b312817d5248', 'matching', 'Questions 21–26', NULL, '<p>Choose <strong>SIX </strong>correct answers, <strong>A-H</strong>, next to questions 21-26.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Subject of Experiments</strong></p>\n<p> </p>\n<p>Steam engine {B too difficult}</p>\n<p> </p>\n<p>Breakfast cereals {G cheap to do}</p>\n<p> </p>\n<p>Bouncing balls {F useful practice for maths}</p>\n<p> </p>\n<p>Making paper {A very boring}</p>\n<p> </p>\n<p>Tie-dying {H takes longer than usual to do}</p>\n<p> </p>\n<p>Glue from milk {E immediate results}</p>", "answerOptions": [{"optionText": "A very boring"}, {"optionText": "B too difficult"}, {"optionText": "C specialised equipment needed"}, {"optionText": "D very expensive"}, {"optionText": "E immediate results"}, {"optionText": "F useful practice for maths"}, {"optionText": "G cheap to do"}, {"optionText": "H takes longer than usual to do"}], "matchingItems": null}', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 3</h2>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Stefan:</strong> Hi Magda, how was your placement?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Magda:</strong> It went really well. The kids really enjoyed the science I did with them.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Stefan:</strong> So did mine. I think they found it very motivating.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Magda:</strong> Yes, the program we had to teach was much better than the old-style science experiments we did at school.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Stefan:</strong> Yes, though I don’t understand why the children should have to build a model of a <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"90\">steam engine</strong>.</span> I tried it with the kids but I couldn’t get it to work.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Magda:</strong> Me neither. And it really shows <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"39\">(21) it’s hard to get any real results [Đáp án B: too difficult]</strong>.</span></p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Stefan:</strong> Yes, and it’s usually the children’s parents rather than the kids themselves who favour that type of experiment. So what experiments did you do?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Magda:</strong> Well, one day a discussion started in class about <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"11\" data-index-in-node=\"57\">breakfast cereals</strong></span>, about which one was best. One child then said that we should test them in class.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Stefan:</strong> That’s a nice idea.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Magda:</strong> Yes, and <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"13\" data-index-in-node=\"16\">(22) it wasn’t expensive [Đáp án G: cheap to do]</strong>.</span></span> We brought four different brands of cereal and had everyone evaluate them for taste, appearance and sogginess in milk.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Stefan:</strong> Another experiment we did—the sports teacher’s idea actually—was to spend a morning seeing how high various<span style=\"background-color: #ffe786;\"> <strong data-path-to-node=\"14\" data-index-in-node=\"116\">bouncing balls</strong> </span>bounced. For example, do new tennis balls bounce higher than old ones?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Magda:</strong> And I guess you got some interesting data?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Stefan:</strong> We did, and they had to make a chart to plot the results<span style=\"text-decoration: underline; background-color: #ffe786;\">. <strong data-path-to-node=\"16\" data-index-in-node=\"66\">(23) It really improved their grasp of charts and graphs and calculation [Đáp án F: useful practice for maths]</strong>.</span> Apparently, they’d had problems understanding the point of graphs in the past.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Magda:</strong> Did all your experiments work out OK?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Stefan:</strong> Well, we had one lesson on<span style=\"background-color: #ffe786;\"> <strong data-path-to-node=\"18\" data-index-in-node=\"35\">making paper</strong> </span>from grass. The children made a terrible mess in the classroom. Whatever they did didn’t work, and it wasn’t because it was difficult. I think it was because <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"18\" data-index-in-node=\"206\">(24) it didn’t engage them at all [Đáp án A: very boring]</strong>.</span> It didn’t seem to motivate them.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Magda:</strong> My <strong data-path-to-node=\"19\" data-index-in-node=\"10\">tie-dying</strong> experiment went well. They had to get a piece of material and twist it into a rope and then dye it.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Stefan:</strong> But don’t you need to spend more than one lesson on that?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Magda:</strong> Yes,<span style=\"background-color: #ffe786;\"> <span style=\"text-decoration: underline;\"><strong data-path-to-node=\"21\" data-index-in-node=\"12\">(25) we did it over three classes [Đáp án H: takes longer than usual to do]</strong>. </span></span>The children really loved it though.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Stefan:</strong> I guess the one experiment that everyone loved in my class was making <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"22\" data-index-in-node=\"78\">glue from milk</strong>.</span> I thought it would be a complete failure, but in fact it worked brilliantly. One reason I suspect is that <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"22\" data-index-in-node=\"200\">(26) they got feedback straight away [Đáp án E: immediate results]</strong></span>. Some children get really restless if they have to wait for anything interesting to happen.</p>\n<hr />\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Stefan:</strong> I see you’ve got a diagram there for one of your experiments.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Magda:</strong> Yes, it was an idea I got from the internet. It was very easy and straightforward to set up. The idea is to make a condenser to extract essences from plants.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Stefan:</strong><span style=\"text-decoration: underline; background-color: #ffe786;\"> The <strong data-path-to-node=\"27\" data-index-in-node=\"12\">large container</strong>‘s made of <strong data-path-to-node=\"27\" data-index-in-node=\"38\">metal</strong> right? <strong data-path-to-node=\"27\" data-index-in-node=\"51\">(27: D)</strong></span></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Magda:</strong> That’s right and it holds the hot water. <span style=\"text-decoration: underline; background-color: #ffe786;\">And it has a <strong data-path-to-node=\"28\" data-index-in-node=\"61\">strainer</strong> which sits inside it. <strong data-path-to-node=\"28\" data-index-in-node=\"92\">(28: F)</strong></span> This is where you put the plant matter. We use plants like Rosemary as the essence you can extract is quite strong.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Stefan:</strong> So what’s the container right at the top?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Magda:</strong> It’s made of glass, it’s where we put the ice. <span style=\"text-decoration: underline; background-color: #ffe786;\">The glass container has a <strong data-path-to-node=\"30\" data-index-in-node=\"80\">drip tip</strong> at the bottom. <strong data-path-to-node=\"30\" data-index-in-node=\"104\">(29: G)</strong></span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Stefan:</strong> What’s that for?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Magda:</strong> It’s where the essence collects.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Stefan:</strong> Where does the essence go then?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Magda:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\">Into the <strong data-path-to-node=\"34\" data-index-in-node=\"16\">dish at the bottom</strong>. It’s made of <strong data-path-to-node=\"34\" data-index-in-node=\"49\">pottery</strong>. <strong data-path-to-node=\"34\" data-index-in-node=\"58\">(30: C)</strong></span></p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Stefan:</strong> Sounds good. I might try it with my class.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('46545127-243f-4e03-8969-64188236e9b3', '194a8ee8-b399-42ca-8ef6-3baf4dc1e427', 'matching', 'Questions 27–33', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Moving rapidly across the desert"}, {"optionText": "ii Recreating the process in a laboratory"}, {"optionText": "iii Strange music created by human movement"}, {"optionText": "iv A potential threat to industry and communications"}, {"optionText": "v Dunes coming together and re-forming"}, {"optionText": "vi Needing a specific combination of conditions"}, {"optionText": "vii A continuous cycle"}, {"optionText": "viii The commonest type of dune"}, {"optionText": "ix Old superstitions demystified"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>27. Paragraph A</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: iv. A potential threat to industry and communications</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn A mô tả các đụn cát khổng lồ đang di chuyển chậm chạp, nhưng sự bò trườn này có thể gây ra <strong>hậu quả nghiêm trọng</strong> (<strong>serious consequences</strong>) nếu chúng đi vào đường ray xe lửa hoặc các lắp đặt dầu khí (industry/communications).</p>\n</li>\n</ul>\n<p><strong>28. Paragraph B</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: viii. The commonest type of dune</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn B tập trung vào loại đụn cát &#8220;linear&#8221; (tuyến tính) và nói rằng chúng chiếm <strong>hơn một nửa</strong> (&#8220;over half&#8221;) diện tích cát, biến chúng thành loại đụn cát phổ biến nhất (<strong>commonest type</strong>).</p>\n</li>\n</ul>\n<p><strong>29. Paragraph C</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: vi. Needing a specific combination of conditions</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn C nói về loại đụn cát &#8220;barchans&#8221; và giải thích rằng chúng <strong>&#8220;only tend to form where you have one-directional winds on the edge of sandy deserts near coastal areas&#8221;</strong>. Đây là một sự kết hợp các điều kiện cụ thể.</p>\n</li>\n</ul>\n<p><strong>30. Paragraph D</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: vii. A continuous cycle</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn D giải thích cơ chế di chuyển của đụn cát theo chu kỳ: hạt cát bị gió thổi lên lưng đụn, tích tụ lại, trượt xuống, bị chôn vùi, rồi lại xuất hiện ở phía sau để <strong>lặp lại quá trình</strong> (<strong>repeat the process</strong>).</p>\n</li>\n</ul>\n<p><strong>31. Paragraph E</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: v. Dunes coming together and re-forming</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn E mô tả cách các đụn cát <strong>tự điều chỉnh hình dạng</strong> (&#8220;regulate its own shape&#8221;) và &#8220;Even when <strong>two dunes collide, they quickly take on their distinctive shapes again</strong>.&#8221;</p>\n</li>\n</ul>\n<p><strong>32. Paragraph F</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: ix. Old superstitions demystified</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn F bắt đầu bằng việc nhắc đến các <strong>huyền thoại địa phương</strong> (<strong>Local legends</strong>) gán tiếng hát của đụn cát cho các linh hồn nguy hiểm, sau đó nhà khoa học Douady đưa ra lời giải thích <strong>thực tế hơn</strong> (pragmatic) về âm thanh đó, tức là giải mã (demystified) các mê tín cũ.</p>\n</li>\n</ul>\n<p><strong>33. Paragraph G</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: ii. Recreating the process in a laboratory</strong></p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đoạn G mô tả cách các nhà khoa học lấy mẫu cát về Pháp và <strong>tái tạo lại âm thanh ở ENS</strong> (<strong>replicate the sound at ENS</strong>), chứng minh rằng họ có thể <strong>tái tạo</strong> quá trình này trong phòng thí nghiệm.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('e4db0ff0-852f-4f04-8440-7b85b5fbc2d6', 'bd92b44d-406e-41b0-bc5f-c0418a5ff2d3', 'fillup', 'Questions 25-27', '<p>Answer the questions below.</p>
<p>Choose <strong>NO MORE THAN THREE WORDS AND/OR A NUMBER</strong> from the text for each answer.</p>
<p>Write your answers in boxes 25-27 on your answer sheet.</p>
<p>To obtain a scholarship, what is the minimum course length? {twenty weeks} or {duration}.</p>
<p>What do scholarship winners receive towards the airfares if they live over 2,500 km from Sydney? {airline vouchers}</p>
<p>Who pays for dependent children to travel? {scholarship holder}.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">25. To obtain a scholarship, what is the minimum course length? — {twenty weeks}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…and are not offered for courses of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"50\">less than twenty weeks duration</strong>.”</em> (Đoạn 1 phần Scholarship)</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi hỏi về độ dài khóa học tối thiểu (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"54\">minimum length</strong>). Bài đọc nói học bổng không dành cho các khóa học ít hơn (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"128\">less than</strong>) 20 tuần. Vậy 20 tuần chính là con số tối thiểu cần thiết.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">26. What do scholarship winners receive towards the airfares if they live over 2,500 km from Sydney? — {airline vouchers}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…if the distance exceeds this amount [2,500 km] you will be provided with <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"88\">airline vouchers</strong>.”</em> (Đoạn 3 phần Scholarship)</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Exceeds” đồng nghĩa với “over”. Khi khoảng cách vượt quá 2.500 km, thay vì vé máy bay khứ hồi thông thường, người thắng giải sẽ nhận được các phiếu đổi vé máy bay (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"177\">airline vouchers</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">27. Who pays for dependent children to travel? — {scholarship holder}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Travel costs or support for dependent children are at the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"70\">scholarship holder’s expense</strong>.”</em> (Đoạn 4 phần Scholarship)</li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “At someone’s expense” nghĩa là người đó phải tự chi trả (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"70\">pays for</strong>). Ở đây, người phải trả tiền cho con cái đi cùng chính là người nhận học bổng (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"158\">scholarship holder</strong>).</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ffb0ae85-9f4e-43b5-8122-4e85ed56a572', 'c0508fac-8a07-40f8-b234-129015847c99', 'radio', 'Questions 28-31', '', '<p>Choose the correct letter<strong> A</strong>, <strong>B</strong>, <strong>C</strong> or<strong> D </strong></p>
<p>Write the correct letter in boxes 28-31 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. Some are more depressing to walk around than others."}, {"option_text": "B. They resemble each other because of the persuasive techniques they use."}, {"option_text": "C. The less successful ones copy the layout of the more successful ones."}, {"option_text": "D. These that are more imaginative are more pleasant to be in."}], "question": "What point does the writer make when comparing supermarkets?"}, {"correct": 0, "options": [{"option_text": "A. allows customers a chance to get used to being in the store."}, {"option_text": "B. displays the most highly-priced goods in the hope customers will buy them."}, {"option_text": "C. notifies regular customers of any changes to the layout."}, {"option_text": "D. encourages customers to buy goods in large quantities."}], "question": "The area just inside the entrance of a supermarket"}, {"correct": 0, "options": [{"option_text": "A. It is a less obvious method of persuasion than some others."}, {"option_text": "B. It distracts shoppers from buying cheaper things such as milk."}, {"option_text": "C. It is a system which shoppers soon get used to."}, {"option_text": "D. It persuades shoppers to spend less time at the back of the store."}], "question": "What does the writer suggest about the placing of popular items in the middle of an aisle?"}, {"correct": 3, "options": [{"option_text": "A. They were less influenced by the marketing of fruit juice than carbonated drinks."}, {"option_text": "B. They were less interested in buying juice than buying carbonated drinks."}, {"option_text": "C. They were more likely to buy products that had information labels."}, {"option_text": "D. They were spending a lot of time trying to decide which to choose."}], "question": "What did the research into the buying of fruit juice show about shoppers?"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. What point does the writer make when comparing supermarkets? — {B} They resemble each other because of the persuasive techniques they use.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…wonder why they are all the same… It is because they are all <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"87\">versed in the science of getting people to buy things</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đặt câu hỏi tại sao các siêu thị lại giống hệt nhau (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"73\">resemble each other</strong>). Câu trả lời không phải vì họ thiếu sáng tạo, mà vì họ đều thông thạo “khoa học thuyết phục người ta mua hàng” (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"206\">persuasive techniques</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. The area just inside the entrance of a supermarket — {A} allows customers a chance to get used to being in the store.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"28\">decompression zone</strong>, where people can <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"65\">slow down and take stock of the surroundings</strong> even if they are regulars.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khu vực ngay sau cửa ra vào được gọi là “vùng giải nén” (decompression zone). Mục đích của nó là để khách hàng đi chậm lại và làm quen với môi trường xung quanh (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"174\">get used to being in the store</strong>) trước khi thực sự bắt đầu mua sắm.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. What does the writer suggest about the placing of popular items in the middle of an aisle? — {A} It is a less obvious method of persuasion than some others.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“But supermarkets know shoppers know this [placing milk at the back], so they use <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"102\">other trick</strong>, like placing popular items halfway along a section so that people have to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"189\">walk all along the aisle</strong>…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mọi người đều đã biết mẹo để sữa ở cuối cửa hàng. Vì vậy, việc để hàng phổ biến ở giữa lối đi là một “mẹo khác” (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"125\">other trick</strong>) – một phương pháp tinh vi và ít lộ liễu hơn (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"183\">less obvious</strong>) nhằm kéo dài thời gian khách ở trong cửa hàng (dwell time).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. What did the research into the buying of fruit juice show about shoppers? — {D} They were spending a lot of time trying to decide which to choose.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…12% of people spent <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"44\">90 seconds looking at juice</strong>, studying the pictures and information… In supermarket decision-making time, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"151\">that is forever</strong>… This implies that shoppers… are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"204\">not sure which to buy</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong thế giới siêu thị, 90 giây là một khoảng thời gian rất dài (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"78\">forever</strong>). Việc khách hàng đứng xem nhãn mác lâu như vậy cho thấy họ đang rất phân vân và tốn nhiều thời gian để quyết định chọn loại nào (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"216\">trying to decide</strong>).</li>\n</ul>"}]', 0);
SET session_replication_role = DEFAULT;
